{
  "name": "LocalLLM Mobile Chat",
  "description": "A mobile-first local ChatGPT-style interface that connects directly to LM Studio or local LLM servers. Supports streaming, history, and model management.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Role = 'user' | 'assistant' | 'system';

export interface Message {
  id: string;
  role: Role;
  content: string;
  timestamp: number;
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  createdAt: number;
  lastModified: number;
  modelId: string;
}

export interface LMStudioModel {
  id: string;
  object: string;
  owned_by: string;
  permission: any[];
}

export interface APIConfig {
  baseUrl: string;
  apiKey: string;
  selectedModel: string;
}

export interface AppState {
  sessions: ChatSession[];
  currentSessionId: string | null;
  config: APIConfig;
  isLoading: boolean;
  availableModels: LMStudioModel[];
}

import { APIConfig } from './types';

export const DEFAULT_CONFIG: APIConfig = {
  baseUrl: 'http://localhost:1234/v1',
  apiKey: 'lm-studio',
  selectedModel: 'default'
};

export const STORAGE_KEYS = {
  SESSIONS: 'llm_chat_sessions',
  CONFIG: 'llm_chat_config',
  THEME: 'llm_chat_theme'
};

import { ChatSession, APIConfig, AppState } from '../types';
import { STORAGE_KEYS, DEFAULT_CONFIG } from '../constants';

export const storageService = {
  saveSessions(sessions: ChatSession[]) {
    localStorage.setItem(STORAGE_KEYS.SESSIONS, JSON.stringify(sessions));
  },

  loadSessions(): ChatSession[] {
    const data = localStorage.getItem(STORAGE_KEYS.SESSIONS);
    return data ? JSON.parse(data) : [];
  },

  saveConfig(config: APIConfig) {
    localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
  },

  loadConfig(): APIConfig {
    const data = localStorage.getItem(STORAGE_KEYS.CONFIG);
    return data ? JSON.parse(data) : DEFAULT_CONFIG;
  }
};

import { APIConfig, Message, LMStudioModel } from '../types';

export const lmStudioService = {
  async fetchModels(config: APIConfig): Promise<LMStudioModel[]> {
    try {
      const response = await fetch(`${config.baseUrl}/models`, {
        headers: { 'Authorization': `Bearer ${config.apiKey}` }
      });
      if (!response.ok) throw new Error('Failed to fetch models');
      const data = await response.json();
      return data.data;
    } catch (error) {
      console.error('Error fetching models:', error);
      return [];
    }
  },

  async streamChat(
    config: APIConfig,
    messages: Message[],
    onToken: (token: string) => void,
    onComplete: (fullContent: string) => void,
    onError: (err: any) => void
  ) {
    try {
      const response = await fetch(`${config.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${config.apiKey}`
        },
        body: JSON.stringify({
          model: config.selectedModel,
          messages: messages.map(m => ({ role: m.role, content: m.content })),
          stream: true,
          temperature: 0.7,
        })
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.statusText}`);
      }

      const reader = response.body?.getReader();
      if (!reader) throw new Error('ReadableStream not supported');

      const decoder = new TextDecoder();
      let fullContent = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n');

        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed || trimmed === 'data: [DONE]') continue;

          if (trimmed.startsWith('data: ')) {
            try {
              const json = JSON.parse(trimmed.slice(6));
              const delta = json.choices[0].delta?.content;
              if (delta) {
                fullContent += delta;
                onToken(delta);
              }
            } catch (e) {
              console.error('Error parsing stream chunk:', e);
            }
          }
        }
      }

      onComplete(fullContent);
    } catch (error) {
      onError(error);
    }
  }
};

