import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  ChatSession, 
  Message, 
  LMStudioModel, 
  APIConfig, 
  Role 
} from './types';
import { storageService } from './services/storageService';
import { lmStudioService } from './services/lmStudioService';
import { 
  SendIcon, 
  MenuIcon, 
  PlusIcon, 
  SettingsIcon, 
  TrashIcon, 
  UserIcon, 
  BotIcon 
} from './components/Icons';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<APIConfig>(storageService.loadConfig());
  const [availableModels, setAvailableModels] = useState<LMStudioModel[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Derived State
  const currentSession = sessions.find(s => s.id === currentSessionId);

  // Initial Load
  useEffect(() => {
    const loadedSessions = storageService.loadSessions();
    setSessions(loadedSessions);
    if (loadedSessions.length > 0) {
      setCurrentSessionId(loadedSessions[0].id);
    } else {
      createNewSession();
    }
    refreshModels();
  }, []);

  // Persist State
  useEffect(() => {
    storageService.saveSessions(sessions);
  }, [sessions]);

  useEffect(() => {
    storageService.saveConfig(config);
  }, [config]);

  // Scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [currentSession?.messages, isStreaming]);

  const refreshModels = async () => {
    const models = await lmStudioService.fetchModels(config);
    setAvailableModels(models);
    if (models.length > 0 && config.selectedModel === 'default') {
      setConfig(prev => ({ ...prev, selectedModel: models[0].id }));
    }
  };

  const createNewSession = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.selectedModel
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setShowSidebar(false);
  };

  const deleteSession = (id: string) => {
    const filtered = sessions.filter(s => s.id !== id);
    setSessions(filtered);
    if (currentSessionId === id) {
      setCurrentSessionId(filtered.length > 0 ? filtered[0].id : null);
      if (filtered.length === 0) createNewSession();
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || !currentSessionId || isStreaming) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        const title = s.messages.length === 0 ? input.substring(0, 30) + (input.length > 30 ? '...' : '') : s.title;
        return {
          ...s,
          title,
          messages: [...s.messages, userMessage],
          lastModified: Date.now()
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setInput('');
    setIsStreaming(true);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: Date.now()
    };

    // Add placeholder assistant message
    setSessions(prev => prev.map(s => 
      s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMessage] } : s
    ));

    await lmStudioService.streamChat(
      config,
      [... (currentSession?.messages || []), userMessage],
      (token) => {
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantMessageId);
            if (idx !== -1) {
              msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token };
            }
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full) => {
        setIsStreaming(false);
      },
      (err) => {
        console.error(err);
        setIsStreaming(false);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantMessageId);
            if (idx !== -1) {
              msgs[idx] = { ...msgs[idx], content: msgs[idx].content + "\n\n*(Error connecting to LM Studio API)*" };
            }
            return { ...s, messages: msgs };
          }
          return s;
        }));
      }
    );
  };

  return (
    <div className="flex h-full w-full max-w-lg mx-auto bg-white dark:bg-slate-900 shadow-xl overflow-hidden relative">
      {/* Sidebar Overlay */}
      {showSidebar && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 transition-opacity"
          onClick={() => setShowSidebar(false)}
        />
      )}

      {/* Sidebar Drawer */}
      <aside className={`
        fixed left-0 top-0 h-full w-4/5 max-w-[300px] bg-slate-50 dark:bg-slate-800 z-50 transform transition-transform duration-300 ease-in-out
        ${showSidebar ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-4 flex flex-col h-full">
          <button 
            onClick={createNewSession}
            className="flex items-center justify-center gap-2 w-full p-3 mb-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium transition-colors"
          >
            <PlusIcon className="w-5 h-5" />
            New Chat
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-2">
            <p className="text-xs font-semibold text-slate-400 uppercase px-2 mb-2">History</p>
            {sessions.map(s => (
              <div 
                key={s.id}
                onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }}
                className={`
                  group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-colors
                  ${currentSessionId === s.id ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300'}
                `}
              >
                <span className="truncate flex-1 text-sm font-medium">{s.title}</span>
                <button 
                  onClick={(e) => { e.stopPropagation(); deleteSession(s.id); }}
                  className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 transition-all"
                >
                  <TrashIcon className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>

          <button 
            onClick={() => { setShowSettings(true); setShowSidebar(false); }}
            className="flex items-center gap-3 p-3 mt-auto rounded-xl hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 transition-colors"
          >
            <SettingsIcon className="w-5 h-5" />
            <span className="text-sm font-medium">Settings</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex flex-col flex-1 h-full w-full relative">
        {/* Header */}
        <header className="flex items-center justify-between px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center gap-3">
            <button onClick={() => setShowSidebar(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
              <MenuIcon className="w-6 h-6 text-slate-600 dark:text-slate-300" />
            </button>
            <div className="flex flex-col">
              <h1 className="text-sm font-bold text-slate-800 dark:text-white truncate max-w-[150px]">
                {currentSession?.title || 'Chat'}
              </h1>
              <span className="text-[10px] text-slate-500 font-medium">
                {config.selectedModel}
              </span>
            </div>
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            <SettingsIcon className="w-5 h-5 text-slate-600 dark:text-slate-300" />
          </button>
        </header>

        {/* Chat Area */}
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-4 space-y-6 no-scrollbar pb-32"
        >
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-4 pt-10">
              <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/30 rounded-3xl flex items-center justify-center">
                <BotIcon className="w-8 h-8 text-indigo-600" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-white">Local LLM Chat</h2>
                <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">Connect to LM Studio and start chatting</p>
              </div>
              <div className="grid grid-cols-2 gap-2 w-full max-w-xs mt-6">
                {['Explain Quantum Physics', 'Write a Python script', 'Healthy meal plan', 'Travel tips for Tokyo'].map((hint) => (
                  <button 
                    key={hint}
                    onClick={() => setInput(hint)}
                    className="p-3 text-[11px] font-medium text-left bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-xl text-slate-600 dark:text-slate-300 transition-colors"
                  >
                    {hint}
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentSession?.messages.map((m) => (
            <div 
              key={m.id} 
              className={`flex w-full ${m.role === 'user' ? 'justify-end' : 'justify-start animate-in fade-in slide-in-from-bottom-2'}`}
            >
              <div className={`flex gap-3 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`
                  flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center
                  ${m.role === 'user' ? 'bg-slate-200 dark:bg-slate-700' : 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600'}
                `}>
                  {m.role === 'user' ? <UserIcon className="w-4 h-4" /> : <BotIcon className="w-4 h-4" />}
                </div>
                <div className={`
                  p-3.5 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap
                  ${m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-tr-none' 
                    : 'bg-slate-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-tl-none'}
                `}>
                  {m.content || (isStreaming && m.role === 'assistant' ? <span className="animate-pulse">● ● ●</span> : '')}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Input Bar */}
        <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-white dark:from-slate-900 via-white/90 dark:via-slate-900/90 to-transparent">
          <div className="flex items-end gap-2 bg-slate-100 dark:bg-slate-800 p-2 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-lg">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSendMessage();
                }
              }}
              placeholder="Message..."
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm max-h-32 p-2 no-scrollbar resize-none text-slate-800 dark:text-slate-200"
              rows={1}
              style={{ height: 'auto' }}
              ref={(el) => {
                if (el) {
                  el.style.height = 'auto';
                  el.style.height = el.scrollHeight + 'px';
                }
              }}
            />
            <button 
              onClick={handleSendMessage}
              disabled={!input.trim() || isStreaming}
              className={`
                p-2 rounded-xl transition-all
                ${!input.trim() || isStreaming ? 'bg-slate-300 dark:bg-slate-700 text-slate-400 cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md active:scale-95'}
              `}
            >
              <SendIcon className="w-5 h-5" />
            </button>
          </div>
          <p className="text-[9px] text-center text-slate-400 mt-2 font-medium">
            Running locally via {config.baseUrl}
          </p>
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setShowSettings(false)} />
          <div className="relative bg-white dark:bg-slate-800 w-full max-w-sm rounded-3xl p-6 shadow-2xl space-y-5 animate-in zoom-in-95 duration-200">
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">Settings</h2>

            <div className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-xs font-bold text-slate-500 uppercase">API Base URL</label>
                <input 
                  type="text" 
                  value={config.baseUrl}
                  onChange={(e) => setConfig({ ...config, baseUrl: e.target.value })}
                  className="w-full p-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-500"
                  placeholder="http://localhost:1234/v1"
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-xs font-bold text-slate-500 uppercase">Selected Model</label>
                <div className="relative">
                  <select 
                    value={config.selectedModel}
                    onChange={(e) => setConfig({ ...config, selectedModel: e.target.value })}
                    className="w-full p-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none appearance-none focus:ring-2 focus:ring-indigo-500"
                  >
                    <option value="default">Default Model</option>
                    {availableModels.map(m => (
                      <option key={m.id} value={m.id}>{m.id}</option>
                    ))}
                  </select>
                  <button 
                    onClick={refreshModels}
                    className="absolute right-2 top-1/2 -translate-y-1/2 text-xs text-indigo-600 font-bold px-2 py-1 hover:bg-indigo-50 rounded"
                  >
                    Refresh
                  </button>
                </div>
              </div>

              <div className="flex items-center gap-2 p-3 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-900/30 rounded-xl">
                <div className="w-2 h-2 rounded-full bg-amber-500 animate-pulse" />
                <p className="text-[10px] text-amber-700 dark:text-amber-400 leading-tight">
                  Ensure <strong>LM Studio</strong> is running and "Enable CORS" is checked in Server settings.
                </p>
              </div>
            </div>

            <button 
              onClick={() => setShowSettings(false)}
