import { APIConfig, Message, LMStudioModel } from '../types';

export const lmStudioService = {
  async fetchModels(config: APIConfig): Promise<LMStudioModel[]> {
    try {
      const response = await fetch(`${config.baseUrl}/models`, {
        headers: { 'Authorization': `Bearer ${config.apiKey}` },
        mode: 'cors'
      });
      if (!response.ok) throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      const data = await response.json();
      return data.data || [];
    } catch (error) {
      console.error('Error fetching models:', error);
      // Re-throw if it's a network error so the UI can handle it specifically
      if (error instanceof TypeError && error.message === 'Failed to fetch') {
        throw new Error('Could not reach LM Studio. Check if the server is running and CORS is enabled.');
      }
      throw error;
    }
  },

  async streamChat(
    config: APIConfig,
    messages: Message[],
    onToken: (token: string) => void,
    onComplete: (fullContent: string) => void,
    onError: (err: any) => void
  ) {
    try {
      const response = await fetch(`${config.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${config.apiKey}`
        },
        body: JSON.stringify({
          model: config.selectedModel,
          messages: messages.map(m => ({ role: m.role, content: m.content })),
          stream: true,
          temperature: 0.7,
        })
      });

      if (!response.ok) {
        const errText = await response.text().catch(() => response.statusText);
        throw new Error(`API Error (${response.status}): ${errText}`);
      }

      const reader = response.body?.getReader();
      if (!reader) throw new Error('ReadableStream not supported in this browser.');

      const decoder = new TextDecoder();
      let fullContent = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n');

        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed || trimmed === 'data: [DONE]') continue;

          if (trimmed.startsWith('data: ')) {
            try {
              const json = JSON.parse(trimmed.slice(6));
              const delta = json.choices[0].delta?.content;
              if (delta) {
                fullContent += delta;
                onToken(delta);
              }
            } catch (e) {
              // Silently ignore malformed chunks to keep stream going
            }
          }
        }
      }

      onComplete(fullContent);
    } catch (error) {
      if (error instanceof TypeError && error.message === 'Failed to fetch') {
        onError(new Error('Network error: Connection refused. Ensure LM Studio server is active and CORS is ON.'));
      } else {
        onError(error);
      }
    }
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  ChatSession, 
  Message, 
  LMStudioModel, 
  APIConfig, 
  Role 
} from './types';
import { storageService } from './services/storageService';
import { lmStudioService } from './services/lmStudioService';
import { 
  SendIcon, 
  MenuIcon, 
  PlusIcon, 
  SettingsIcon, 
  TrashIcon, 
  UserIcon, 
  BotIcon 
} from './components/Icons';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<APIConfig>(storageService.loadConfig());
  const [availableModels, setAvailableModels] = useState<LMStudioModel[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'connected' | 'error' | 'checking'>('checking');
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Derived State
  const currentSession = sessions.find(s => s.id === currentSessionId);

  // Initial Load
  useEffect(() => {
    const loadedSessions = storageService.loadSessions();
    setSessions(loadedSessions);
    if (loadedSessions.length > 0) {
      setCurrentSessionId(loadedSessions[0].id);
    } else {
      createNewSession();
    }
    refreshModels();
  }, []);

  // Persist State
  useEffect(() => {
    storageService.saveSessions(sessions);
  }, [sessions]);

  useEffect(() => {
    storageService.saveConfig(config);
  }, [config]);

  // Scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [currentSession?.messages, isStreaming]);

  const refreshModels = async () => {
    setConnectionStatus('checking');
    setErrorMessage(null);
    try {
      const models = await lmStudioService.fetchModels(config);
      setAvailableModels(models);
      setConnectionStatus('connected');
      if (models.length > 0 && (config.selectedModel === 'default' || !models.find(m => m.id === config.selectedModel))) {
        setConfig(prev => ({ ...prev, selectedModel: models[0].id }));
      }
    } catch (error: any) {
      console.error(error);
      setConnectionStatus('error');
      setErrorMessage(error.message || 'Failed to connect to LM Studio');
      setAvailableModels([]);
    }
  };

  const createNewSession = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.selectedModel
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setShowSidebar(false);
  };

  const deleteSession = (id: string) => {
    const filtered = sessions.filter(s => s.id !== id);
    setSessions(filtered);
    if (currentSessionId === id) {
      setCurrentSessionId(filtered.length > 0 ? filtered[0].id : null);
      if (filtered.length === 0) createNewSession();
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || !currentSessionId || isStreaming) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        const title = s.messages.length === 0 ? input.substring(0, 30) + (input.length > 30 ? '...' : '') : s.title;
        return {
          ...s,
          title,
          messages: [...s.messages, userMessage],
          lastModified: Date.now()
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setInput('');
    setIsStreaming(true);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: Date.now()
    };

    // Add placeholder assistant message
    setSessions(prev => prev.map(s => 
      s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMessage] } : s
    ));

    await lmStudioService.streamChat(
      config,
      [... (currentSession?.messages || []), userMessage],
      (token) => {
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantMessageId);
            if (idx !== -1) {
              msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token };
            }
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full) => {
        setIsStreaming(false);
      },
      (err) => {
        console.error(err);
        setIsStreaming(false);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantMessageId);
            if (idx !== -1) {
              msgs[idx] = { 
                ...msgs[idx], 
                content: msgs[idx].content + `\n\n**Connection Error:** ${err.message || 'Could not reach LM Studio'}.\n\n*Troubleshooting:* Ensure LM Studio server is running, CORS is enabled, and the URL is correct.` 
              };
            }
            return { ...s, messages: msgs };
          }
          return s;
        }));
      }
    );
  };

