        ${showSidebar ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-4 flex flex-col h-full">
          <button 
            onClick={createNewSession}
            className="flex items-center justify-center gap-2 w-full p-3 mb-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium transition-colors"
          >
            <PlusIcon className="w-5 h-5" />
            New Chat
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-2">
            <p className="text-xs font-semibold text-slate-400 uppercase px-2 mb-2">History</p>
            {sessions.map(s => (
              <div 
                key={s.id}
                onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }}
                className={`
                  group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-colors
                  ${currentSessionId === s.id ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300'}
                `}
              >
                <span className="truncate flex-1 text-sm font-medium">{s.title}</span>
                <button 
                  onClick={(e) => { e.stopPropagation(); deleteSession(s.id); }}
                  className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500 transition-all"
                >
                  <TrashIcon className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>

          <button 
            onClick={() => { setShowSettings(true); setShowSidebar(false); }}
            className="flex items-center gap-3 p-3 mt-auto rounded-xl hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 transition-colors"
          >
            <SettingsIcon className="w-5 h-5" />
            <span className="text-sm font-medium">Settings</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex flex-col flex-1 h-full w-full relative">
        {/* Header */}
        <header className="flex items-center justify-between px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center gap-3">
            <button onClick={() => setShowSidebar(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
              <MenuIcon className="w-6 h-6 text-slate-600 dark:text-slate-300" />
