import { APIConfig, Message, LMStudioModel } from '../types';

export const lmStudioService = {
  async fetchModels(config: APIConfig): Promise<LMStudioModel[]> {
    const isHttpsPage = window.location.protocol === 'https:';
    const isHttpTarget = config.baseUrl.startsWith('http:');

    try {
      const response = await fetch(`${config.baseUrl}/models`, {
        headers: { 
          'Authorization': `Bearer ${config.apiKey}`,
          'Accept': 'application/json'
        },
        mode: 'cors',
        cache: 'no-cache'
      });

      if (!response.ok) throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      const data = await response.json();
      return data.data || [];
    } catch (error) {
      console.error('Detailed fetch error:', error);

      if (error instanceof TypeError && error.message === 'Failed to fetch') {
        if (isHttpsPage && isHttpTarget) {
          throw new Error('Mixed Content Error: Browsers block HTTPS sites from accessing local HTTP APIs. You must either run this app over HTTP or use a secure tunnel (like Ngrok/Cloudflare) for LM Studio.');
        }
        throw new Error('Connection Refused: Ensure LM Studio is running, the "Local Server" is started, and "CORS" is enabled in LM Studio settings.');
      }
      throw error;
    }
  },

  async streamChat(
    config: APIConfig,
    messages: Message[],
    onToken: (token: string) => void,
    onComplete: (fullContent: string) => void,
    onError: (err: any) => void
  ) {
    try {
      const response = await fetch(`${config.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${config.apiKey}`
        },
        body: JSON.stringify({
          model: config.selectedModel,
          messages: messages.map(m => ({ role: m.role, content: m.content })),
          stream: true,
          temperature: 0.7,
        }),
        mode: 'cors'
      });

      if (!response.ok) {
        const errText = await response.text().catch(() => response.statusText);
        throw new Error(`API Error (${response.status}): ${errText}`);
      }

      const reader = response.body?.getReader();
      if (!reader) throw new Error('ReadableStream not supported.');

      const decoder = new TextDecoder();
      let fullContent = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n');

        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed || trimmed === 'data: [DONE]') continue;

          if (trimmed.startsWith('data: ')) {
            try {
              const json = JSON.parse(trimmed.slice(6));
              const delta = json.choices[0].delta?.content;
              if (delta) {
                fullContent += delta;
                onToken(delta);
              }
            } catch (e) {}
          }
        }
      }

      onComplete(fullContent);
    } catch (error) {
      if (error instanceof TypeError && error.message === 'Failed to fetch') {
        onError(new Error('Network error: Browsers block local requests if CORS is missing or if there is a Protocol Mismatch (HTTPS -> HTTP).'));
      } else {
        onError(error);
      }
    }
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  ChatSession, 
  Message, 
  LMStudioModel, 
  APIConfig, 
  Role 
} from './types';
import { storageService } from './services/storageService';
import { lmStudioService } from './services/lmStudioService';
import { 
  SendIcon, 
  MenuIcon, 
  PlusIcon, 
  SettingsIcon, 
  TrashIcon, 
  UserIcon, 
  BotIcon 
} from './components/Icons';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<APIConfig>(storageService.loadConfig());
  const [availableModels, setAvailableModels] = useState<LMStudioModel[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'connected' | 'error' | 'checking'>('checking');
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const isHttps = window.location.protocol === 'https:';

  // Derived State
  const currentSession = sessions.find(s => s.id === currentSessionId);

  // Initial Load
  useEffect(() => {
    const loadedSessions = storageService.loadSessions();
    setSessions(loadedSessions);
    if (loadedSessions.length > 0) {
      setCurrentSessionId(loadedSessions[0].id);
    } else {
      createNewSession();
    }
    refreshModels();
  }, []);

  // Persist State
  useEffect(() => {
    storageService.saveSessions(sessions);
  }, [sessions]);

  useEffect(() => {
    storageService.saveConfig(config);
  }, [config]);

  // Scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [currentSession?.messages, isStreaming]);

  const refreshModels = async () => {
    setConnectionStatus('checking');
    setErrorMessage(null);
    try {
      const models = await lmStudioService.fetchModels(config);
      setAvailableModels(models);
      setConnectionStatus('connected');
      if (models.length > 0 && (config.selectedModel === 'default' || !models.find(m => m.id === config.selectedModel))) {
        setConfig(prev => ({ ...prev, selectedModel: models[0].id }));
      }
    } catch (error: any) {
      console.error(error);
      setConnectionStatus('error');
      setErrorMessage(error.message || 'Failed to connect to LM Studio');
      setAvailableModels([]);
    }
  };

  const createNewSession = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.selectedModel
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setShowSidebar(false);
  };

  const deleteSession = (id: string) => {
    const filtered = sessions.filter(s => s.id !== id);
    setSessions(filtered);
    if (currentSessionId === id) {
      setCurrentSessionId(filtered.length > 0 ? filtered[0].id : null);
      if (filtered.length === 0) createNewSession();
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || !currentSessionId || isStreaming) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    const updatedSessions = sessions.map(s => {
      if (s.id === currentSessionId) {
        const title = s.messages.length === 0 ? input.substring(0, 30) + (input.length > 30 ? '...' : '') : s.title;
        return {
          ...s,
          title,
          messages: [...s.messages, userMessage],
          lastModified: Date.now()
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setInput('');
    setIsStreaming(true);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: Date.now()
    };

    setSessions(prev => prev.map(s => 
      s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMessage] } : s
    ));

    await lmStudioService.streamChat(
      config,
      [... (currentSession?.messages || []), userMessage],
      (token) => {
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantMessageId);
            if (idx !== -1) {
              msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token };
            }
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full) => {
        setIsStreaming(false);
      },
      (err) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantMessageId);
            if (idx !== -1) {
              msgs[idx] = { 
                ...msgs[idx], 
                content: msgs[idx].content + `\n\n❌ **Error:** ${err.message}` 
              };
            }
            return { ...s, messages: msgs };
          }
          return s;
        }));
      }
    );
  };

  return (
    <div className="flex h-full w-full max-w-lg mx-auto bg-white dark:bg-slate-900 shadow-xl overflow-hidden relative border-x border-slate-200 dark:border-slate-800">
      {showSidebar && (
        <div className="fixed inset-0 bg-black/50 z-40 transition-opacity" onClick={() => setShowSidebar(false)} />
      )}

      <aside className={`fixed left-0 top-0 h-full w-4/5 max-w-[300px] bg-slate-50 dark:bg-slate-800 z-50 transform transition-transform duration-300 ease-in-out ${showSidebar ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-4 flex flex-col h-full">
          <button onClick={createNewSession} className="flex items-center justify-center gap-2 w-full p-3 mb-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium shadow-sm transition-all active:scale-95">
            <PlusIcon className="w-5 h-5" /> New Chat
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-2">
            <p className="text-xs font-semibold text-slate-400 uppercase px-2 mb-2">History</p>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-colors ${currentSessionId === s.id ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300'}`}>
                <span className="truncate flex-1 text-sm font-medium">{s.title}</span>
                <button onClick={(e) => { e.stopPropagation(); deleteSession(s.id); }} className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-500"><TrashIcon className="w-4 h-4" /></button>
              </div>
            ))}
          </div>

          <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-3 p-3 mt-auto rounded-xl hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-300 transition-colors">
            <SettingsIcon className="w-5 h-5" /> <span className="text-sm font-medium">Settings</span>
          </button>
        </div>
      </aside>

      <main className="flex flex-col flex-1 h-full w-full relative">
        <header className="flex items-center justify-between px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center gap-3">
            <button onClick={() => setShowSidebar(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
              <MenuIcon className="w-6 h-6 text-slate-600 dark:text-slate-300" />
            </button>
            <div className="flex flex-col">
              <h1 className="text-sm font-bold text-slate-800 dark:text-white truncate max-w-[150px]">{currentSession?.title || 'Chat'}</h1>
              <div className="flex items-center gap-1.5">
                <span className={`w-1.5 h-1.5 rounded-full ${connectionStatus === 'connected' ? 'bg-green-500' : connectionStatus === 'error' ? 'bg-red-500' : 'bg-slate-400 animate-pulse'}`} />
                <span className="text-[10px] text-slate-500 font-medium truncate max-w-[120px]">{config.selectedModel}</span>
              </div>
            </div>
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            <SettingsIcon className="w-5 h-5 text-slate-600 dark:text-slate-300" />
          </button>
        </header>

        {connectionStatus === 'error' && (
          <div className="bg-red-50 dark:bg-red-900/20 border-b border-red-100 dark:border-red-900/30 p-3 flex flex-col gap-2">
            <div className="flex items-center justify-between gap-2">
              <p className="text-[11px] text-red-700 dark:text-red-400 font-bold uppercase tracking-tight">Connection Issue Detected</p>
              <button onClick={refreshModels} className="text-[10px] bg-red-600 text-white px-2 py-1 rounded font-bold">Retry Connection</button>
            </div>
            <p className="text-[11px] text-red-600/80 dark:text-red-400/80 leading-snug">{errorMessage}</p>
          </div>
        )}

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-6 no-scrollbar pb-32">
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-6 pt-10 px-4">
              <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/30 rounded-3xl flex items-center justify-center animate-bounce duration-1000">
                <BotIcon className="w-8 h-8 text-indigo-600" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-white tracking-tight">Ready to Chat?</h2>
                <p className="text-sm text-slate-500 dark:text-slate-400 mt-2 max-w-[200px] mx-auto">I'm your local AI assistant running on your hardware.</p>
              </div>

              {connectionStatus === 'error' && (
                <div className="p-4 bg-white dark:bg-slate-800 rounded-2xl border-2 border-red-100 dark:border-red-900/30 text-left space-y-3 w-full shadow-sm">
                   <h3 className="text-xs font-black text-red-600 dark:text-red-400 uppercase tracking-widest">How to Fix:</h3>
                   <div className="space-y-2 text-[11px] text-slate-600 dark:text-slate-400">
                     <p>• <strong>Browser Security:</strong> {isHttps ? "Since this site uses HTTPS, you MUST use an HTTPS tunnel (like Cloudflare Tunnel) to connect to LM Studio, or browsers will block the request." : "Open LM Studio and start the server."}</p>
                     <p>• <strong>CORS:</strong> Ensure "Cross-Origin Resource Sharing" is enabled in LM Studio Server Settings.</p>
                     <p>• <strong>Target:</strong> Check if <code>{config.baseUrl}</code> matches your LM Studio server address.</p>
                   </div>
                </div>
              )}

              <div className="grid grid-cols-2 gap-2 w-full max-w-xs">
                {['Write a poem about code', 'How does React work?', 'Plan a 3-day trip', 'Fix my CSS bug'].map((hint) => (
                  <button key={hint} onClick={() => setInput(hint)} className="p-3 text-[11px] font-semibold text-left bg-slate-100 dark:bg-slate-800 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-xl text-slate-600 dark:text-slate-300 border border-transparent hover:border-indigo-200 transition-all">
                    {hint}
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentSession?.messages.map((m) => (
            <div key={m.id} className={`flex w-full ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`flex gap-3 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center shadow-sm ${m.role === 'user' ? 'bg-slate-200 dark:bg-slate-700' : 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600'}`}>
                  {m.role === 'user' ? <UserIcon className="w-4 h-4" /> : <BotIcon className="w-4 h-4" />}
                </div>
                <div className={`p-3.5 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap shadow-sm ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-50 dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-tl-none border border-slate-200/50 dark:border-slate-700/50'}`}>
                  {m.content || (isStreaming && m.role === 'assistant' ? <span className="animate-pulse">● ● ●</span> : '')}
