                <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Active Model</label>
                <select value={config.selectedModel} onChange={(e) => setConfig({ ...config, selectedModel: e.target.value })} className="w-full p-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none appearance-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50" disabled={availableModels.length === 0}>
                  {availableModels.length === 0 ? <option value="default">Refresh to find models</option> : availableModels.map(m => <option key={m.id} value={m.id}>{m.id}</option>)}
                </select>
              </div>

              {isHttps && (
                <div className="p-3 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-900/30 rounded-xl">
                  <h4 className="text-[10px] font-bold text-amber-700 dark:text-amber-400 uppercase mb-1">⚠️ Security Restriction</h4>
                  <p className="text-[10px] text-slate-600 dark:text-slate-400 leading-normal">
                    You are on an <strong>HTTPS</strong> site. Browsers block requests to <strong>HTTP</strong> local servers. Use a tunnel (Cloudflare/Ngrok) to get an HTTPS URL for LM Studio.
                  </p>
                </div>
              )}
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full p-3 bg-indigo-600 text-white rounded-xl font-bold transition-all active:scale-95 shadow-lg shadow-indigo-600/20">
              Save & Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

