import { GoogleGenAI } from "@google/genai";
import { Message, AppConfig } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const localInference = {
  // Simulates loading a model into VRAM
  async loadModel(modelId: string): Promise<void> {
    return new Promise((resolve) => {
      // Simulation of memory allocation and weight loading
      setTimeout(resolve, 1500); 
    });
  },

  async streamResponse(
    config: AppConfig,
    history: Message[],
    onToken: (token: string, tps: number) => void,
    onComplete: (full: string) => void,
    onError: (err: any) => void
  ) {
    try {
      const modelName = 'gemini-3-flash-preview';

      const contents = history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const startTime = Date.now();
      let tokenCount = 0;

      const responseStream = await ai.models.generateContentStream({
        model: modelName,
        contents: contents,
        config: {
          temperature: 0.7,
          topP: 0.95,
          topK: 40,
        }
      });

      let fullText = "";
      for await (const chunk of responseStream) {
        const text = chunk.text;
        if (text) {
          fullText += text;
          tokenCount += text.split(' ').length; // Rough estimation
          const elapsed = (Date.now() - startTime) / 1000;
          const tps = Math.round(tokenCount / elapsed);
          onToken(text, tps);
        }
      }

      onComplete(fullText);
    } catch (error) {
      onError(error);
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { ChatSession, Message, LocalModel, AppConfig, DeviceStats } from './types';
