  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isModelLoading, setIsModelLoading] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  // Simulation: Hardware Monitoring
  useEffect(() => {
    const interval = setInterval(() => {
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (Math.random() * 0.1 - 0.05)).toFixed(2),
        temp: Math.floor(35 + Math.random() * 10)
      }));
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  // Initial Load
  useEffect(() => {
    const loadedSessions = storageService.loadSessions();
    setSessions(loadedSessions);
    if (loadedSessions.length > 0) {
      setCurrentSessionId(loadedSessions[0].id);
    } else {
      createNewSession();
    }
  }, []);

  // Persist
  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);

  // Auto-scroll
  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming]);

  const createNewSession = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'Local Session',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setShowSidebar(false);
  };

  const handleSendMessage = async () => {
    if (!input.trim() || isStreaming || isModelLoading) return;

    // Check if model needs loading
    if (!isStreaming) {
      setIsModelLoading(true);
      await localInference.loadModel(config.activeModelId);
      setIsModelLoading(false);
    }

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input, timestamp: Date.now() };

    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s,
      messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 30) : s.title,
      lastModified: Date.now()
    } : s));

    setInput('');
    setIsStreaming(true);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now() };

    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      () => setIsStreaming(false),
      (err) => {
        setIsStreaming(false);
        console.error(err);
      }
    );
  };

  return (
    <div className="flex h-full w-full max-w-lg mx-auto bg-slate-50 dark:bg-slate-950 overflow-hidden relative font-sans text-slate-900 dark:text-slate-100">

      {/* Sidebar */}
      {showSidebar && <div className="fixed inset-0 bg-black/60 z-40 backdrop-blur-sm" onClick={() => setShowSidebar(false)} />}
      <aside className={`fixed left-0 top-0 h-full w-72 bg-white dark:bg-slate-900 z-50 transform transition-transform duration-300 ease-out ${showSidebar ? 'translate-x-0' : '-translate-x-full'} shadow-2xl`}>
        <div className="p-5 flex flex-col h-full">
          <button onClick={createNewSession} className="flex items-center justify-center gap-2 w-full p-4 mb-6 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold shadow-lg shadow-indigo-500/30 transition-all active:scale-95">
            <PlusIcon className="w-5 h-5" /> New Local Chat
          </button>
          <div className="flex-1 overflow-y-auto no-scrollbar space-y-3">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Local History</h3>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-3.5 rounded-xl cursor-pointer transition-all ${currentSessionId === s.id ? 'bg-indigo-50 dark:bg-indigo-500/10 text-indigo-600 dark:text-indigo-400' : 'hover:bg-slate-100 dark:hover:bg-slate-800'}`}>
                <span className="truncate flex-1 text-sm font-semibold">{s.title}</span>
                <TrashIcon className="w-4 h-4 opacity-0 group-hover:opacity-100 text-slate-400 hover:text-red-500 transition-opacity" onClick={(e) => { e.stopPropagation(); setSessions(prev => prev.filter(x => x.id !== s.id)); }} />
              </div>
            ))}
          </div>
          <div className="mt-auto pt-4 border-t border-slate-200 dark:border-slate-800">
            <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl mb-3">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
              <div className="text-[10px] font-bold">DEVICE: {deviceStats.ramUsage}GB / {deviceStats.totalRam}GB RAM</div>
            </div>
            <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-3 p-3 w-full rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
              <SettingsIcon className="w-5 h-5" /> <span className="text-sm font-bold">Engine Settings</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Main Chat Area */}
      <main className="flex flex-col flex-1 h-full w-full relative">
        <header className="px-5 py-4 flex flex-col gap-2 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl sticky top-0 z-30">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <button onClick={() => setShowSidebar(true)} className="p-2 -ml-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl"><MenuIcon className="w-6 h-6" /></button>
              <div>
                <h1 className="text-sm font-black tracking-tight">{currentSession?.title || 'Chat'}</h1>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-tighter">On-Device Inference • {config.activeModelId}</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
               <div className="hidden sm:flex flex-col items-end">
                 <span className="text-[9px] font-black text-slate-400 uppercase">GPU Temp</span>
                 <span className={`text-[10px] font-bold ${deviceStats.temp > 45 ? 'text-orange-500' : 'text-green-500'}`}>{deviceStats.temp}°C</span>
               </div>
               <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl"><SettingsIcon className="w-5 h-5" /></button>
            </div>
          </div>

          {isModelLoading && (
            <div className="w-full bg-indigo-500/10 h-1.5 rounded-full overflow-hidden">
               <div className="bg-indigo-600 h-full animate-progress-indefinite" style={{ width: '40%' }}></div>
            </div>
          )}
        </header>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-8 no-scrollbar pb-36">
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-6 pt-12">
              <div className="w-20 h-20 bg-gradient-to-tr from-indigo-600 to-violet-500 rounded-3xl flex items-center justify-center shadow-xl shadow-indigo-500/20 rotate-3 animate-pulse">
                <BotIcon className="w-10 h-10 text-white" />
              </div>
              <div className="space-y-2">
                <h2 className="text-2xl font-black tracking-tighter">Self-Contained AI</h2>
                <p className="text-sm text-slate-500 dark:text-slate-400 font-medium max-w-[240px] mx-auto leading-relaxed">
                  No internet needed. Your data stays on this device. Powered by {config.activeModelId}.
                </p>
              </div>
              <div className="grid grid-cols-2 gap-3 w-full">
                {['Creative Poem', 'Python Script', 'Fix code', 'Health Plan'].map(h => (
                  <button key={h} onClick={() => setInput(h)} className="p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl text-[11px] font-bold text-slate-600 dark:text-slate-400 shadow-sm hover:border-indigo-500 hover:text-indigo-600 transition-all text-left">
                    {h}
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentSession?.messages.map(m => (
            <div key={m.id} className={`flex w-full ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`flex flex-col gap-1.5 max-w-[88%] ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className="flex items-center gap-2 mb-1 px-1">
                  <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{m.role}</span>
                  {m.tokensPerSec && <span className="text-[9px] font-bold bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded-full text-indigo-500">{m.tokensPerSec} tok/s</span>}
                </div>
                <div className={`p-4 rounded-3xl text-sm leading-relaxed shadow-sm ${
                  m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 rounded-tl-none border border-slate-100 dark:border-slate-800'
                }`}>
                  {m.content || (isStreaming && <span className="animate-pulse flex gap-1"><span className="w-1.5 h-1.5 bg-current rounded-full"></span><span className="w-1.5 h-1.5 bg-current rounded-full delay-75"></span><span className="w-1.5 h-1.5 bg-current rounded-full delay-150"></span></span>)}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Floating Input */}
        <div className="absolute bottom-0 left-0 right-0 p-5 bg-gradient-to-t from-slate-50 dark:from-slate-950 via-slate-50/90 dark:via-slate-950/90 to-transparent">
          <div className="bg-white dark:bg-slate-900 p-3 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-2xl flex items-end gap-2 focus-within:ring-2 ring-indigo-500/50 transition-all">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isModelLoading ? "Loading model weights..." : "Type your message..."}
              disabled={isModelLoading}
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm p-2 no-scrollbar resize-none max-h-40 min-h-[44px]"
              rows={1}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); } }}
            />
            <button 
              onClick={handleSendMessage}
              disabled={!input.trim() || isStreaming || isModelLoading}
              className={`p-3.5 rounded-2xl transition-all shadow-lg ${!input.trim() || isStreaming || isModelLoading ? 'bg-slate-100 dark:bg-slate-800 text-slate-400' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-90'}`}
            >
              <SendIcon className="w-5 h-5" />
            </button>
          </div>
          <div className="flex justify-center items-center gap-4 mt-3">
             <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
               <div className={`w-1.5 h-1.5 rounded-full ${deviceStats.gpuEnabled ? 'bg-indigo-500' : 'bg-slate-400'}`} />
               Local Neural Engine
             </span>
             {isStreaming && <span className="text-[9px] font-black text-indigo-500 uppercase tracking-widest">{currentTps} TPS</span>}
          </div>
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in">
          <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md" onClick={() => setShowSettings(false)} />
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-t-[32px] sm:rounded-[32px] p-8 shadow-2xl space-y-6 animate-in slide-in-from-bottom-10 sm:zoom-in-95">
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-black tracking-tight">Engine Control</h2>
              <button onClick={() => setShowSettings(false)} className="text-[11px] font-bold text-slate-400 hover:text-slate-600 uppercase">Close</button>
            </div>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Active Model</label>
                <div className="space-y-2">
                  {AVAILABLE_MODELS.map(m => (
                    <div 
                      key={m.id}
                      onClick={() => setConfig({ ...config, activeModelId: m.id })}
                      className={`p-4 rounded-2xl border-2 cursor-pointer transition-all ${config.activeModelId === m.id ? 'border-indigo-600 bg-indigo-50/50 dark:bg-indigo-500/10' : 'border-slate-100 dark:border-slate-800 hover:border-slate-300'}`}
                    >
                      <div className="flex justify-between items-start mb-1">
                        <span className="text-sm font-black">{m.name}</span>
                        <span className="text-[10px] font-bold bg-slate-200 dark:bg-slate-700 px-1.5 py-0.5 rounded uppercase">{m.size}</span>
                      </div>
                      <p className="text-[11px] text-slate-500 leading-tight">{m.description}</p>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase px-1 tracking-widest">Precision</label>
                   <select 
                     value={config.quantization}
                     onChange={(e) => setConfig({ ...config, quantization: e.target.value as any })}
                     className="w-full p-3 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl text-xs font-bold focus:ring-2 ring-indigo-500"
                   >
                     <option value="4-bit">4-bit (Fastest)</option>
                     <option value="8-bit">8-bit (Better)</option>
                     <option value="fp16">FP16 (Pure)</option>
                   </select>
                 </div>
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase px-1 tracking-widest">Acceleration</label>
                   <div 
                     onClick={() => setConfig({ ...config, useGpu: !config.useGpu })}
                     className={`w-full p-3 rounded-2xl text-xs font-bold text-center cursor-pointer transition-all ${config.useGpu ? 'bg-indigo-600 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}
                   >
                     {config.useGpu ? 'Metal/CUDA ON' : 'CPU Only'}
                   </div>
                 </div>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full py-4 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl font-black text-sm tracking-tight transition-transform active:scale-95">
              Confirm Changes
            </button>
          </div>
        </div>
      )}

      <style>{`
        @keyframes progress-indefinite {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(250%); }
        }
        .animate-progress-indefinite {
          animation: progress-indefinite 2s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

