        <div className="p-6 flex flex-col h-full">
          <h2 className="text-lg font-black tracking-tighter mb-6 bg-gradient-to-r from-indigo-500 to-violet-500 bg-clip-text text-transparent italic">NEURAL PULSE</h2>
          <button onClick={createNewSession} className="flex items-center justify-center gap-2 w-full p-4 mb-8 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">
            <PlusIcon className="w-5 h-5" /> Start New Pulse
          </button>
          <div className="flex-1 overflow-y-auto no-scrollbar space-y-4">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Memory Vault</h3>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-3.5 rounded-2xl cursor-pointer transition-all ${currentSessionId === s.id ? 'bg-indigo-50 dark:bg-indigo-500/10 text-indigo-600 dark:text-indigo-400' : 'hover:bg-slate-100 dark:hover:bg-slate-800'}`}>
                <span className="truncate flex-1 text-sm font-bold">{s.title}</span>
                <TrashIcon className="w-4 h-4 opacity-0 group-hover:opacity-100 text-slate-400 hover:text-red-500" onClick={(e) => { e.stopPropagation(); setSessions(prev => prev.filter(x => x.id !== s.id)); }} />
              </div>
            ))}
          </div>
          <div className="mt-auto pt-6 border-t border-slate-100 dark:border-slate-800">
            <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-3 p-3 w-full rounded-2xl hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
              <SettingsIcon className="w-5 h-5 text-slate-400" /> <span className="text-sm font-bold">Inference Engine</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Main UI */}
      <main className="flex flex-col flex-1 h-full w-full relative">
        <header className="px-5 py-4 border-b border-slate-100 dark:border-white/5 bg-white/80 dark:bg-[#08080c]/80 backdrop-blur-2xl sticky top-0 z-30">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button onClick={() => setShowSidebar(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-xl"><MenuIcon className="w-6 h-6" /></button>
              <div>
                <h1 className="text-sm font-black tracking-tight flex items-center gap-2">
                  {currentSession?.title} 
                  <span className={`w-1.5 h-1.5 rounded-full ${deviceStats.temp > 50 ? 'bg-red-500' : 'bg-green-500'} animate-pulse`} />
                </h1>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className="text-[9px] font-black text-slate-500 uppercase tracking-tighter bg-slate-100 dark:bg-white/5 px-1.5 py-0.5 rounded">{config.profile}</span>
                  <span className="text-[9px] font-bold text-slate-400">{config.activeModelId}</span>
                </div>
              </div>
            </div>
            <div className="flex flex-col items-end gap-1">
               <div className="flex items-center gap-3">
