import { GoogleGenAI } from "@google/genai";
import { Message, AppConfig, IntelligenceProfile, ReasoningStep, MemoryChunk } from '../types';
import { INTELLIGENCE_PROFILES } from '../constants';

// Simulated Local Documents for RAG
const LOCAL_KNOWLEDGE: MemoryChunk[] = [
  { id: '1', text: 'NeuralPulse runs on ARM architectures using Llama.cpp backend.', source: 'System Architecture Manual' },
  { id: '2', text: 'To save battery, switch to Eco mode which disables heavy reasoning steps.', source: 'Power Settings' },
  { id: '3', text: 'RAG works by embedding queries and matching them against SQLite vector storage.', source: 'Developer API' }
];

export const localInference = {
  async loadModel(modelId: string): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, 800)); // Optimized weight loading
  },

  async streamResponse(
    config: AppConfig,
    history: Message[],
    onStepUpdate: (steps: ReasoningStep[]) => void,
    onToken: (token: string, tps: number) => void,
    onComplete: (full: string, sources?: string[]) => void,
    onError: (err: any) => void
  ) {
    try {
      // Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const profile = INTELLIGENCE_PROFILES[config.profile];
      const userQuery = history[history.length - 1].content;

      // STAGE 1: Reasoning & Planning
      const steps: ReasoningStep[] = [
        { label: 'Analyzing Intent', status: 'active' },
        { label: 'Retrieving Local Memory', status: 'pending' },
        { label: 'Synthesizing Response', status: 'pending' }
      ];
      onStepUpdate([...steps]);
      await new Promise(r => setTimeout(r, 600));

      // STAGE 2: RAG Retrieval (Simulated)
      steps[0].status = 'complete';
      steps[1].status = 'active';
      onStepUpdate([...steps]);

      let sources: string[] = [];
      let contextInjection = "";

      if (config.useRAG) {
        const matches = LOCAL_KNOWLEDGE.filter(doc => 
          userQuery.toLowerCase().includes(doc.text.split(' ')[0].toLowerCase()) || 
          userQuery.toLowerCase().includes('neural')
        );
        if (matches.length > 0) {
          sources = matches.map(m => m.source);
          contextInjection = `[LOCAL CONTEXT: ${matches.map(m => m.text).join(' ')}]`;
        }
      }
      await new Promise(r => setTimeout(r, 400));

      // STAGE 3: Final Execution
      steps[1].status = 'complete';
      steps[2].status = 'active';
      onStepUpdate([...steps]);

      const systemInstruction = `
        You are an on-device AI assistant named NeuralPulse. 
        Current Context: ${contextInjection}
        Instruction: Be concise, mobile-friendly, and leverage the context if available.
        Your hardware is ${config.useGpu ? 'GPU' : 'CPU'} accelerated.
      `;

      const contents = history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const startTime = Date.now();
      let tokenCount = 0;

      const responseStream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview', // Pro for high quality reasoning simulation
        contents: contents,
        config: {
          systemInstruction,
          temperature: 0.8,
          thinkingConfig: { thinkingBudget: profile.thinkingBudget },
          maxOutputTokens: profile.maxTokens,
        }
      });

      let fullText = "";
      for await (const chunk of responseStream) {
        if (steps[2].status !== 'complete') {
          steps[2].status = 'complete';
          onStepUpdate([...steps]);
        }

        const text = chunk.text;
        if (text) {
          fullText += text;
          tokenCount += text.length / 4; // Estimate tokens
          const elapsed = (Date.now() - startTime) / 1000;
          const tps = Math.round(tokenCount / elapsed);
          onToken(text, tps);
        }
      }

      onComplete(fullText, sources);
    } catch (error) {
      onError(error);
    }
  }
};

