import { GoogleGenAI } from "@google/genai";
import { Message, AppConfig, ReasoningStep, MemoryEntry } from '../types';
import { STORAGE_KEYS } from '../constants';

export const localInference = {
  // Simple local cognitive memory persistence
  async saveToMemory(text: string): Promise<void> {
    const memory: MemoryEntry[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY) || '[]');
    const newEntry: MemoryEntry = {
      id: Date.now().toString(),
      text,
      timestamp: Date.now(),
      importance: 0.8
    };
    memory.push(newEntry);
    // Keep only the most relevant/recent 50 entries for mobile RAM safety
    if (memory.length > 50) memory.shift();
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(memory));
  },

  async retrieveFromMemory(query: string): Promise<string[]> {
    const memory: MemoryEntry[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY) || '[]');
    // Simple keyword-based retrieval as a placeholder for local vector search
    const queryTerms = query.toLowerCase().split(' ');
    return memory
      .filter(entry => queryTerms.some(term => entry.text.toLowerCase().includes(term) && term.length > 3))
      .slice(-3)
      .map(entry => entry.text);
  },

  async streamResponse(
    config: AppConfig,
    history: Message[],
    onStepUpdate: (steps: ReasoningStep[]) => void,
    onToken: (token: string, tps: number) => void,
    onComplete: (full: string, sources: string[]) => void,
    onError: (err: any) => void
  ) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const userQuery = history[history.length - 1].content;

    const steps: ReasoningStep[] = [
      { label: 'Neural Planning (Phi-3)', status: 'active' },
      { label: 'Cognitive Memory Retrieval', status: 'pending' },
      { label: 'Final Inference (Qwen 7B)', status: 'pending' }
    ];

    try {
      onStepUpdate([...steps]);

      // STAGE 1: Planning
      await new Promise(r => setTimeout(r, 800));
      steps[0].status = 'complete';
      steps[1].status = 'active';
      onStepUpdate([...steps]);

      // STAGE 2: Cognitive Memory Retrieval
      let retrievedContext = "";
      let sources: string[] = [];
      if (config.useCognitiveMemory) {
        const memoryMatches = await this.retrieveFromMemory(userQuery);
        if (memoryMatches.length > 0) {
          retrievedContext = memoryMatches.join('\n');
          sources = ["Local Cognitive Memory"];
        }
      }
      await new Promise(r => setTimeout(r, 400));
      steps[1].status = 'complete';
      steps[2].status = 'active';
      onStepUpdate([...steps]);

      // STAGE 3: Final Inference
      const systemInstruction = `
        YOU ARE: NeuralPulse Core (Architect: Qwen 2.5 Coder 7B).
        MODE: Personal, Offline, Private.
        CONTEXT_MEMORY: ${retrievedContext || "None available."}

        RULES:
        1. Be highly technical when asked for code.
        2. Use the provided context to adapt to the user's personal style.
        3. Hardware is ARM-optimized 4-bit GGUF.
      `;

      const contents = history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const startTime = Date.now();
      let tokenCount = 0;

      const responseStream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview', // High-fidelity simulation of Qwen 7B performance
        contents: contents,
        config: {
          systemInstruction,
          temperature: config.profile === 'Eco' ? 0.3 : 0.7,
          thinkingConfig: { 
            thinkingBudget: config.profile === 'Performance' ? 32000 : 8000 
          }
        }
      });

      let fullText = "";
      for await (const chunk of responseStream) {
        const text = chunk.text;
        if (text) {
          fullText += text;
          tokenCount += text.length / 3.5;
          const elapsed = (Date.now() - startTime) / 1000;
          onToken(text, Math.round(tokenCount / elapsed));
        }
      }

      steps[2].status = 'complete';
      onStepUpdate([...steps]);
      onComplete(fullText, sources);

      // Post-process: Decide if we should save this interaction to memory
      if (fullText.length > 200) {
        await this.saveToMemory(`User: ${userQuery}\nAssistant: ${fullText.slice(0, 300)}...`);
      }

    } catch (err) {
      onError(err);
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ChatSession, Message, LocalModel, 
  AppConfig, DeviceStats, ReasoningStep, PerformanceMode 
} from './types';
import { AVAILABLE_MODELS, DEFAULT_CONFIG, STORAGE_KEYS } from './constants';
import { storageService } from './services/storageService';
import { localInference } from './services/localInference';
import { 
  SendIcon, MenuIcon, PlusIcon, SettingsIcon, 
  TrashIcon, UserIcon, BotIcon 
} from './components/Icons';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [deviceStats, setDeviceStats] = useState<DeviceStats>({ 
    ramUsage: 1.4, totalRam: 12, temp: 37, npuLoad: 8, batteryLevel: 92 
  });
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [activeSteps, setActiveSteps] = useState<ReasoningStep[]>([]);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    const loaded = storageService.loadSessions();
    if (loaded.length > 0) {
      setSessions(loaded);
      setCurrentSessionId(loaded[0].id);
    } else createNewSession();
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (isStreaming ? 0.8 : -0.2)).toFixed(2),
        temp: isStreaming ? Math.min(prev.temp + 1.2, 58) : Math.max(prev.temp - 0.4, 32),
        npuLoad: isStreaming ? 94 : 2,
        batteryLevel: prev.batteryLevel - (isStreaming ? 0.05 : 0.005)
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isStreaming]);

  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming, activeSteps]);

  const createNewSession = () => {
    const s: ChatSession = {
      id: Date.now().toString(),
      title: 'Neural Core Alpha',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [s, ...prev]);
    setCurrentSessionId(s.id);
    setShowSidebar(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input, timestamp: Date.now() };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s, messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 24) : s.title
    } : s));

    setInput('');
    setIsStreaming(true);
    setActiveSteps([]);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now(), reasoningSteps: [] };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (steps) => setActiveSteps(steps),
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps, reasoningSteps: activeSteps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full, sources) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => s.id === currentSessionId ? {
          ...s, messages: s.messages.map(m => m.id === assistantId ? { ...m, sources, reasoningSteps: [] } : m)
        } : s));
      },
      (err) => { setIsStreaming(false); console.error(err); }
    );
  };

  return (
    <div className="flex h-full w-full max-w-lg mx-auto bg-[#0a0a0f] text-slate-100 overflow-hidden relative font-sans selection:bg-indigo-500/30">

      {/* Sidebar - Personal Vault */}
      {showSidebar && <div className="fixed inset-0 bg-black/80 z-40 backdrop-blur-md" onClick={() => setShowSidebar(false)} />}
      <aside className={`fixed left-0 top-0 h-full w-72 bg-[#0d0d14] z-50 transform transition-transform duration-500 cubic-bezier(0.4, 0, 0.2, 1) ${showSidebar ? 'translate-x-0' : '-translate-x-full'} border-r border-white/5`}>
        <div className="p-7 flex flex-col h-full">
          <div className="flex items-center gap-3 mb-8">
            <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-indigo-600 to-violet-600 flex items-center justify-center shadow-lg shadow-indigo-600/20">
              <BotIcon className="w-6 h-6 text-white" />
            </div>
            <h2 className="text-xl font-black tracking-tighter italic">NEURAL PULSE</h2>
          </div>

          <button onClick={createNewSession} className="flex items-center justify-center gap-2 w-full p-4 mb-8 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">
            <PlusIcon className="w-5 h-5" /> Initialize Core
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-5">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-2">Cognitive Vault</h3>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-all ${currentSessionId === s.id ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 shadow-inner' : 'hover:bg-white/5 border border-transparent'}`}>
                <span className="truncate flex-1 text-sm font-bold tracking-tight">{s.title}</span>
                <TrashIcon className="w-4 h-4 opacity-0 group-hover:opacity-100 text-slate-500 hover:text-red-500" onClick={(e) => { e.stopPropagation(); setSessions(prev => prev.filter(x => x.id !== s.id)); }} />
              </div>
            ))}
          </div>

          <div className="mt-auto pt-6 border-t border-white/5">
            <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-3 p-4 w-full rounded-2xl hover:bg-white/5 transition-colors">
              <SettingsIcon className="w-5 h-5 text-slate-500" /> <span className="text-sm font-bold">Neural Parameters</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Main Experience */}
      <main className="flex flex-col flex-1 h-full w-full relative">
        <header className="px-6 py-5 border-b border-white/5 bg-[#0a0a0f]/90 backdrop-blur-2xl sticky top-0 z-30 flex items-center justify-between">
          <div className="flex items-center gap-4">
