            <div>
              <h1 className="text-sm font-black tracking-tight">{currentSession?.title}</h1>
              <div className="flex items-center gap-2 mt-1">
                 <div className="flex items-center gap-1.5">
                   <div className={`w-1.5 h-1.5 rounded-full ${deviceStats.temp > 50 ? 'bg-orange-500' : 'bg-green-500'}`} />
                   <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{Math.round(deviceStats.batteryLevel)}% PWR</span>
                 </div>
                 <span className="text-[9px] font-black text-indigo-500/80 bg-indigo-500/5 px-2 py-0.5 rounded-full">{config.profile}</span>
