};

import { GoogleGenAI } from "@google/genai";
import { Message, AppConfig, ReasoningStep, MemoryEntry } from '../types';
import { STORAGE_KEYS } from '../constants';

export const localInference = {
  // Offline Personal Cognitive Memory: Learns style and preferences
  async learnFromInteraction(query: string, response: string): Promise<void> {
    const memory: MemoryEntry[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY) || '[]');

    // Simple heuristic: If response contains code, save coding style. 
    // If user expresses preference ("I like..."), save preference.
    let type: MemoryEntry['type'] = 'knowledge';
    if (response.includes('```')) type = 'style';
    if (query.toLowerCase().includes('i prefer') || query.toLowerCase().includes('use ')) type = 'preference';

    const newEntry: MemoryEntry = {
      id: Date.now().toString(),
      text: `Context: ${query.slice(0, 100)}... -> Learned: ${response.slice(0, 200)}...`,
      type,
      timestamp: Date.now(),
      importance: type === 'preference' ? 1.0 : 0.6
    };

    memory.push(newEntry);
    if (memory.length > 30) memory.shift(); // RAM-safe rolling memory
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(memory));
  },

  async retrieveCognitiveMemory(query: string): Promise<string[]> {
    const memory: MemoryEntry[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY) || '[]');
    const queryTerms = query.toLowerCase().split(' ').filter(t => t.length > 3);

    return memory
      .filter(entry => queryTerms.some(term => entry.text.toLowerCase().includes(term)))
      .sort((a, b) => b.importance - a.importance)
      .slice(0, 2)
      .map(e => e.text);
  },

  async streamResponse(
    config: AppConfig,
    history: Message[],
    onStepUpdate: (steps: ReasoningStep[]) => void,
    onToken: (token: string, tps: number) => void,
    onComplete: (full: string, sources: string[]) => void,
    onError: (err: any) => void
  ) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const userQuery = history[history.length - 1].content;

    const steps: ReasoningStep[] = [
      { label: 'Intent Decomposition (Phi-3)', status: 'active' },
      { label: 'Identity Memory Sync', status: 'pending' },
      { label: 'Architecture Refinement (Qwen 7B)', status: 'pending' }
    ];

    try {
      onStepUpdate([...steps]);

      // STAGE 1: Intent Detection (Simulation of Phi-3 Mini)
      await new Promise(r => setTimeout(r, 700));
      steps[0].status = 'complete';
      steps[1].status = 'active';
      onStepUpdate([...steps]);

      // STAGE 2: Personal Cognitive Retrieval (The Moat)
      let personalContext = "";
      let sources: string[] = [];
      if (config.useCognitiveMemory) {
        const memory = await this.retrieveCognitiveMemory(userQuery);
        if (memory.length > 0) {
          personalContext = `USER STYLE/PREFS FOUND: ${memory.join(' | ')}`;
          sources = ["Identity Vault"];
        }
      }
      await new Promise(r => setTimeout(r, 300));
      steps[1].status = 'complete';
      steps[2].status = 'active';
      onStepUpdate([...steps]);

      // STAGE 3: Final Execution (Qwen 2.5 Coder simulation)
      const systemInstruction = `
        SYSTEM: NeuralPulse V3 (Engine: Qwen 2.5 Coder 7B).
        ENVIRONMENT: 100% Offline, Private, ARM64 Optimized.
        PERSONAL_CONTEXT: ${personalContext || "Generic profile."}

        FORMATTING RULES:
        - Use clean Markdown. 
        - Double line breaks between paragraphs.
        - High-contrast code blocks with language identifiers.
        - Bulleted lists for reasoning.
      `;

      const contents = history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const startTime = Date.now();
      let tokenCount = 0;

      const responseStream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: contents,
        config: {
          systemInstruction,
          temperature: config.profile === 'Eco' ? 0.2 : 0.75,
          thinkingConfig: { 
            thinkingBudget: config.profile === 'Performance' ? 32000 : 12000 
          }
        }
      });

      let fullText = "";
      for await (const chunk of responseStream) {
        const text = chunk.text;
        if (text) {
          fullText += text;
          tokenCount += text.length / 4;
          const elapsed = (Date.now() - startTime) / 1000;
          onToken(text, Math.round(tokenCount / elapsed));
        }
      }

      steps[2].status = 'complete';
      onStepUpdate([...steps]);
      onComplete(fullText, sources);

      // Post-Process: Adaptive Learning
      if (fullText.length > 150) {
        this.learnFromInteraction(userQuery, fullText);
      }

    } catch (err) {
      onError(err);
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ChatSession, Message, LocalModel, 
  AppConfig, DeviceStats, ReasoningStep, PerformanceMode 
} from './types';
import { AVAILABLE_MODELS, DEFAULT_CONFIG } from './constants';
import { storageService } from './services/storageService';
import { localInference } from './services/localInference';
import { 
  SendIcon, MenuIcon, PlusIcon, SettingsIcon, 
  TrashIcon, BotIcon 
} from './components/Icons';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [deviceStats, setDeviceStats] = useState<DeviceStats>({ 
    ramUsage: 1.2, totalRam: 12, temp: 34, npuLoad: 4, batteryLevel: 98 
  });
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [activeSteps, setActiveSteps] = useState<ReasoningStep[]>([]);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    const loaded = storageService.loadSessions();
    if (loaded.length > 0) {
      setSessions(loaded);
      setCurrentSessionId(loaded[0].id);
    } else createNewSession();

    const loadedConfig = storageService.loadConfig();
    if (loadedConfig) setConfig(loadedConfig);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (isStreaming ? 0.6 : -0.1)).toFixed(2),
        temp: isStreaming ? Math.min(prev.temp + 1.5, 54) : Math.max(prev.temp - 0.4, 30),
        npuLoad: isStreaming ? 92 : 3,
        batteryLevel: Math.max(0, prev.batteryLevel - (isStreaming ? 0.08 : 0.005))
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isStreaming]);

  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);
  useEffect(() => { storageService.saveConfig(config); }, [config]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming, activeSteps]);

  const createNewSession = () => {
    const s: ChatSession = {
      id: Date.now().toString(),
      title: 'Neural Core Alpha',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [s, ...prev]);
    setCurrentSessionId(s.id);
    setShowSidebar(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input, timestamp: Date.now() };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s, messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 24) : s.title
    } : s));

    setInput('');
    setIsStreaming(true);
    setActiveSteps([]);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now(), reasoningSteps: [] };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (steps) => setActiveSteps(steps),
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps, reasoningSteps: activeSteps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full, sources) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => s.id === currentSessionId ? {
          ...s, messages: s.messages.map(m => m.id === assistantId ? { ...m, sources, reasoningSteps: [], isPersonalized: sources.length > 0 } : m)
        } : s));
      },
      (err) => { setIsStreaming(false); console.error(err); }
    );
  };

  const renderContent = (content: string) => {
    // Basic Markdown Parser (simplified for demo)
    return content.split('\n\n').map((paragraph, i) => {
      if (paragraph.startsWith('```')) {
        const lines = paragraph.split('\n');
        const code = lines.slice(1, -1).join('\n');
        return (
          <div key={i} className="my-5 rounded-2xl overflow-hidden border border-white/10 shadow-xl">
             <div className="bg-[#1e1e2e] px-4 py-2 flex items-center justify-between border-b border-white/5">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{lines[0].replace('```', '') || 'code'}</span>
                <button className="text-[10px] text-indigo-400 font-bold hover:text-indigo-300">COPY</button>
             </div>
             <pre className="bg-[#0a0a0f] p-4 overflow-x-auto no-scrollbar font-mono text-[13px] leading-relaxed text-indigo-300/90 whitespace-pre-wrap">
                {code || paragraph}
             </pre>
          </div>
        );
      }
      return <p key={i} className="mb-4 last:mb-0 leading-relaxed font-medium">{paragraph}</p>;
    });
  };

  return (
    <div className="flex h-full w-full max-w-lg mx-auto bg-[#08080c] text-slate-100 overflow-hidden relative font-sans">

      {/* Sidebar - Personal Cognitive Vault */}
      {showSidebar && <div className="fixed inset-0 bg-black/80 z-40 backdrop-blur-md" onClick={() => setShowSidebar(false)} />}
      <aside className={`fixed left-0 top-0 h-full w-72 bg-[#0d0d14] z-50 transform transition-transform duration-500 cubic-bezier(0.4, 0, 0.2, 1) ${showSidebar ? 'translate-x-0' : '-translate-x-full'} border-r border-white/5`}>
        <div className="p-7 flex flex-col h-full">
          <div className="flex items-center gap-3 mb-10">
            <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-indigo-600 to-indigo-800 flex items-center justify-center shadow-lg shadow-indigo-600/20">
              <BotIcon className="w-6 h-6 text-white" />
            </div>
