                <button onClick={() => navigator.clipboard.writeText(code)} className="text-[9px] text-indigo-400 font-bold uppercase">Copy</button>
             </div>
             <div className="p-3 overflow-x-auto no-scrollbar">
                <pre className="text-[11px] leading-relaxed text-indigo-300/90 whitespace-pre">{code}</pre>
