          </div>
        );
      }
      return <p key={i} className="mb-3 last:mb-0 leading-[1.6] font-medium text-[12px] text-slate-200 whitespace-pre-wrap">{trimmed}</p>;
    });
  };

  return (
    <div className="flex h-full w-full max-w-md mx-auto bg-[#07070a] text-slate-100 overflow-hidden relative font-sans">

      {/* Sidebar */}
