             <button onClick={() => setShowSettings(true)} className="p-1.5 hover:bg-white/5 rounded-xl"><SettingsIcon className="w-4 h-4 text-slate-500" /></button>
          </div>
        </header>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-8 no-scrollbar pb-40 scroll-smooth">
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-8 py-8 animate-in fade-in duration-700">
              <div className="w-16 h-16 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-2xl">
                <BotIcon className="w-8 h-8 text-white" />
              </div>
              <div className="space-y-1 max-w-[180px]">
                <h2 className="text-lg font-black tracking-tighter text-white uppercase">Ready to Assist</h2>
                <p className="text-[10px] text-slate-500 font-bold">100% Offline | Identity-Aware | Multi-Agentic</p>
              </div>
              <div className="flex flex-col gap-2 w-full max-w-[200px]">
                {['Optimize code', 'Strategy plan', 'Search summary'].map(h => (
                  <button key={h} onClick={() => setInput(h)} className="p-3 bg-[#101017] border border-white/5 rounded-xl text-[10px] font-black text-slate-500 hover:text-indigo-400 transition-all text-left flex items-center justify-between">
                    {h} <PlusIcon className="w-3.5 h-3.5 text-indigo-500" />
