export default App;

pub enum TaskType {
    Code,
    Reasoning,
    Chat,
    Search,
}

pub fn classify(prompt: &str) -> TaskType {
    let p = prompt.to_lowercase();

    if p.contains("write code")
        || p.contains("function")
        || p.contains("bug")
        || p.contains("typescript")
        || p.contains("rust")
        || p.contains("code")
    {
        TaskType::Code
    } else if p.contains("why")
        || p.contains("explain")
        || p.contains("analyze")
        || p.contains("reason")
    {
        TaskType::Reasoning
    } else if p.contains("search")
        || p.contains("find")
        || p.contains("lookup")
    {
        TaskType::Search
    } else {
        TaskType::Chat
    }
}

use crate::router::TaskType;

pub fn system_prompt(task: TaskType) -> &'static str {
    match task {
        TaskType::Code =>
            "You are an expert software engineer. Respond with clean, correct, production-quality code. Use markdown and code blocks.",
        TaskType::Reasoning =>
            "You are a careful analytical assistant. Think step by step, explain clearly, and structure your response.",
        TaskType::Search =>
            "You summarize and synthesize known information accurately and concisely.",
        TaskType::Chat =>
            "You are a helpful, friendly AI assistant. Respond naturally and clearly.",
    }
}

pub enum ModelKind {
    Fast,
    Coder,
    Reasoner,
}

pub fn model_path(kind: ModelKind) -> &'static str {
    match kind {
        ModelKind::Fast => "models/phi-2.q4.gguf",
        ModelKind::Coder => "models/qwen2.5-coder-7b.q4.gguf",
        ModelKind::Reasoner => "models/mistral-7b-instruct.q4.gguf",
    }
}

use crate::router::TaskType;
use crate::models::ModelKind;

pub fn select_model(task: TaskType) -> ModelKind {
    match task {
        TaskType::Code => ModelKind::Coder,
        TaskType::Reasoning => ModelKind::Reasoner,
        _ => ModelKind::Fast,
    }
}

pub struct Plan {
    pub steps: Vec<String>,
}

pub fn plan(prompt: &str) -> Plan {
    // Dynamic planning logic
    let steps = vec![
        "Understand context".into(),
        "Retrieve identity memory".into(),
        "Formulate optimized strategy".into(),
        "Execute core reasoning".into(),
        "Verify & Output".into(),
    ];
    Plan { steps }
}

use crate::agent::Plan;

pub fn execute(plan: Plan, user_prompt: &str) -> String {
    let mut context = String::new();

    for step in plan.steps {
        context.push_str(&format!("Step: {}\n", step));
    }

    context.push_str("\nUser Request:\n");
    context.push_str(user_prompt);

    context
}

// Conceptual Native Module Wrapper
const Voice = (window as any).Voice || {
  start: (locale: string) => console.log("Native Voice start:", locale),
  stop: () => console.log("Native Voice stop"),
  onSpeechResults: (results: any) => console.log("Native Speech Result:", results)
};

export function startListening(onText: (t: string) => void) {
  Voice.onSpeechResults = (e: any) => {
    if (e.value && e.value.length > 0) {
