import { GoogleGenAI } from "@google/genai";
import { Message, AppConfig, ReasoningStep, MemoryEntry, TaskType, Plan, ToolCall } from '../types';
import { STORAGE_KEYS, TASK_SPECIFIC_PROMPTS } from '../constants';
import { appendToken } from '../app/utils/streamBuffer';

export const localInference = {
  classifyTask(prompt: string): TaskType {
    const p = prompt.toLowerCase();
    if (p.includes("write code") || p.includes("function") || p.includes("bug") || p.includes("typescript") || p.includes("rust") || p.includes("code")) {
      return 'Code';
    } else if (p.includes("why") || p.includes("explain") || p.includes("analyze") || p.includes("reason")) {
      return 'Reasoning';
    } else if (p.includes("search") || p.includes("find") || p.includes("lookup")) {
      return 'Search';
    } else {
      return 'Chat';
    }
  },

  detectToolCall(text: string): ToolCall | null {
    // Matches "tool:write_file:content" or similar structure
    if (text.includes("tool:")) {
      const parts = text.split(':');
      if (parts.length >= 3) {
        return {
          name: parts[1],
          input: parts.slice(2).join(':')
        };
      }
    }
    return null;
  },

  createPlan(prompt: string, taskType: TaskType): Plan {
    const commonSteps = ["Understand context", "Retrieve identity memory"];
    let specificSteps: string[] = [];

    switch (taskType) {
      case 'Code':
        specificSteps = ["Architect solution", "Implement logic", "Verify Tool Output"];
        break;
      case 'Reasoning':
        specificSteps = ["Break into logic blocks", "Analyze constraints", "Synthesize conclusion"];
        break;
      case 'Search':
        specificSteps = ["Identify keywords", "Synthesize findings"];
        break;
      default:
        specificSteps = ["Formulate response"];
    }

    return { steps: [...commonSteps, ...specificSteps] };
  },

  async learnFromInteraction(query: string, response: string): Promise<void> {
    const memory: MemoryEntry[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY) || '[]');
    let type: MemoryEntry['type'] = 'knowledge';
    if (response.includes('```')) type = 'style';
    if (query.toLowerCase().includes('i prefer') || query.toLowerCase().includes('use ')) type = 'preference';

    const newEntry: MemoryEntry = {
      id: Date.now().toString(),
      text: `Context: ${query.slice(0, 100)}... -> Learned: ${response.slice(0, 200)}...`,
      type,
      timestamp: Date.now(),
      importance: type === 'preference' ? 1.0 : 0.6,
      isPinned: false
    };

    memory.push(newEntry);
    if (memory.length > 50) memory.shift();
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(memory));
  },

  async retrieveCognitiveMemory(query: string): Promise<string[]> {
    const memory: MemoryEntry[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY) || '[]');
    const queryTerms = query.toLowerCase().split(' ').filter(t => t.length > 3);

    return memory
      .filter(entry => entry.isPinned || queryTerms.some(term => entry.text.toLowerCase().includes(term)))
      .sort((a, b) => b.importance - a.importance)
      .slice(0, 4)
      .map(e => e.text);
  },

  async streamResponse(
    config: AppConfig,
    history: Message[],
    onStepUpdate: (steps: ReasoningStep[]) => void,
    onToken: (token: string, tps: number) => void,
    onComplete: (full: string, sources: string[], toolCalls?: ToolCall[]) => void,
    onError: (err: any) => void
  ) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const userQuery = history[history.length - 1].content;

    const taskType = this.classifyTask(userQuery);
    const plan = this.createPlan(userQuery, taskType);
    const steps: ReasoningStep[] = plan.steps.map(s => ({ label: s, status: 'pending' }));

    try {
      steps[0].status = 'active';
      onStepUpdate([...steps]);

      await new Promise(r => setTimeout(r, 400));
      steps[0].status = 'complete';
      steps[1].status = 'active';
      onStepUpdate([...steps]);

      let personalContext = "";
      let sources: string[] = [];
      if (config.useCognitiveMemory) {
        const memory = await this.retrieveCognitiveMemory(userQuery);
        if (memory.length > 0) {
          personalContext = `USER STYLE/PREFS: ${memory.join(' | ')}`;
          sources = ["Identity Vault"];
        }
      }

      steps[1].status = 'complete';
      steps[2].status = 'active';
      onStepUpdate([...steps]);

      const systemInstruction = `
        SYSTEM: NeuralPulse V3 (Active Task: ${taskType}).
        MODE: ${TASK_SPECIFIC_PROMPTS[taskType]}
        PERSONAL_CONTEXT: ${personalContext || "Generic profile."}
        TOOLS: You can use tools by prefixing your response with 'tool:[name]:[input]'. Available: write_file, read_file.
      `;

      const contents = history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const startTime = Date.now();
      let tokenCount = 0;

      const responseStream = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: contents,
        config: {
          systemInstruction,
          temperature: config.profile === 'Eco' ? 0.2 : 0.8,
          thinkingConfig: { 
            thinkingBudget: config.profile === 'Performance' ? 32000 : 16000 
          }
        }
      });

      let fullText = "";
      for await (const chunk of responseStream) {
        const text = chunk.text;
        if (text) {
          fullText += text;
          tokenCount += text.length / 4;
          const elapsed = (Date.now() - startTime) / 1000;

          // Use our batched stream buffer for performance
          appendToken(text, (batchedText) => {
            onToken(batchedText, Math.round(tokenCount / elapsed));
          });
        }
      }

      // MARK: Tool Detection
      const toolCall = this.detectToolCall(fullText);
      let toolResults: ToolCall[] = [];
      if (toolCall) {
        toolCall.result = `Simulated execution of ${toolCall.name} success.`;
        toolResults.push(toolCall);
      }

      steps.forEach(s => s.status = 'complete');
      onStepUpdate([...steps]);
      onComplete(fullText, sources, toolResults);

      if (fullText.length > 50) {
        this.learnFromInteraction(userQuery, fullText);
      }

    } catch (err) {
      onError(err);
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ChatSession, Message, LocalModel, 
  AppConfig, DeviceStats, ReasoningStep, PerformanceMode, TaskType, MemoryEntry
} from './types';
import { AVAILABLE_MODELS, DEFAULT_CONFIG, STORAGE_KEYS } from './constants';
import { storageService } from './services/storageService';
import { localInference } from './services/localInference';
import { initLLM } from './native/LocalLLM';
import { 
  SendIcon, MenuIcon, PlusIcon, SettingsIcon, 
  TrashIcon, BotIcon, MicIcon, SpeakerIcon
} from './components/Icons';
import { MemoryPanel } from './app/components/MemoryPanel';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [deviceStats, setDeviceStats] = useState<DeviceStats>({ 
    ramUsage: 1.2, totalRam: 12, temp: 34, npuLoad: 4, batteryLevel: 98 
  });
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [activeSteps, setActiveSteps] = useState<ReasoningStep[]>([]);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showMemory, setShowMemory] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [memories, setMemories] = useState<MemoryEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    initLLM("/data/data/com.neurpulse/models/qwen2.5-coder-7b.gguf");
    const loaded = storageService.loadSessions();
    if (loaded.length > 0) {
      setSessions(loaded);
      setCurrentSessionId(loaded[0].id);
    } else createNewSession();

    const loadedConfig = storageService.loadConfig();
    if (loadedConfig) setConfig(loadedConfig);

    const loadedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
    if (loadedMemories) setMemories(JSON.parse(loadedMemories));
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      // Throttling based on thermal state (simulated)
      const multiplier = config.profile === 'Performance' ? 1.5 : config.profile === 'Eco' ? 0.5 : 1;
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (isStreaming ? 0.4 * multiplier : -0.1)).toFixed(2),
        temp: isStreaming ? Math.min(prev.temp + 0.5 * multiplier, 55) : Math.max(prev.temp - 0.2, 30),
        npuLoad: isStreaming ? 75 * multiplier : 2,
        batteryLevel: Math.max(0, prev.batteryLevel - (isStreaming ? 0.03 * multiplier : 0.001))
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isStreaming, config.profile]);

  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);
  useEffect(() => { storageService.saveConfig(config); }, [config]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming, activeSteps]);

  const createNewSession = () => {
    const s: ChatSession = {
      id: Date.now().toString(),
      title: 'Neural Core Alpha',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [s, ...prev]);
    setCurrentSessionId(s.id);
    setShowSidebar(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const taskType = localInference.classifyTask(input);
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: input, 
      timestamp: Date.now(),
      taskType
    };

    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s, messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 24) : s.title
    } : s));

    setInput('');
    setIsStreaming(true);
    setActiveSteps([]);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now(), reasoningSteps: [] };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (newSteps) => setActiveSteps(newSteps),
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full, sources, toolCalls) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => s.id === currentSessionId ? {
          ...s, messages: s.messages.map(m => m.id === assistantId ? { ...m, sources, toolCalls, reasoningSteps: [], isPersonalized: sources.length > 0 } : m)
        } : s));

        // Update local memory list
        const updatedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
        if (updatedMemories) setMemories(JSON.parse(updatedMemories));

        if (config.voiceEnabled) speak(full);
      },
      (err) => { setIsStreaming(false); console.error(err); }
    );
  };

  const deleteMemory = (id: string) => {
    const updated = memories.filter(m => m.id !== id);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const pinMemory = (id: string) => {
    const updated = memories.map(m => m.id === id ? { ...m, isPinned: !m.isPinned } : m);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const toggleListening = () => {
    if (isListening) setIsListening(false);
    else {
      setIsListening(true);
      setTimeout(() => {
        if (isListening) setInput("Analyze my local workspace files.");
        setIsListening(false);
      }, 1500);
    }
  };

  const speak = (text: string) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text.slice(0, 150));
      window.speechSynthesis.speak(utterance);
    }
  };

  const renderContent = (content: string) => {
    const blocks = content.split(/(\n\n|```[\s\S]*?```)/g);
    return blocks.map((block, i) => {
      const trimmed = block.trim();
      if (!trimmed) return null;
      if (trimmed.startsWith('```')) {
        const lines = trimmed.split('\n');
        const lang = lines[0].replace('```', '').trim() || 'code';
        const code = lines.slice(1, -1).join('\n');
        return (
          <div key={i} className="my-2 rounded-lg overflow-hidden border border-white/10 bg-[#0a0a0f] font-mono shadow-sm">
             <div className="bg-[#1a1a24] px-2.5 py-1 flex items-center justify-between border-b border-white/5">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">{lang}</span>
                <button onClick={() => navigator.clipboard.writeText(code)} className="text-[8px] text-indigo-400 font-bold uppercase">Copy</button>
             </div>
             <div className="p-2.5 overflow-x-auto no-scrollbar">
                <pre className="text-[10.5px] leading-relaxed text-indigo-300/90 whitespace-pre">{code}</pre>
             </div>
          </div>
        );
      }
      return <p key={i} className="mb-2.5 last:mb-0 leading-[1.55] font-medium text-[12px] text-slate-200 whitespace-pre-wrap">{trimmed}</p>;
    });
  };

