    </div>
  );
};

export default App;

use std::collections::HashMap;

pub type ToolFn = fn(String) -> String;

pub struct ToolRegistry {
    tools: HashMap<String, ToolFn>,
}

impl ToolRegistry {
    pub fn new() -> Self {
        let mut tools = HashMap::new();

        tools.insert("write_file".into(), write_file as ToolFn);
        tools.insert("read_file".into(), read_file as ToolFn);

        Self { tools }
    }

    pub fn call(&self, name: &str, input: String) -> Option<String> {
        self.tools.get(name).map(|f| f(input))
    }
}

fn write_file(input: String) -> String {
    // In a real mobile app, this would use a sandbox path
    // std::fs::write("workspace/output.txt", input).unwrap();
    "File written successfully in workspace vault.".into()
}

fn read_file(_: String) -> String {
    // "std::fs::read_to_string("workspace/output.txt").unwrap_or_default()"
    "Sample file content from neural vault.".into()
}

pub fn detect_tool_call(text: &str) -> Option<(String, String)> {
    if text.starts_with("tool:") {
        let parts: Vec<&str> = text.splitn(3, ':').collect();
        if parts.len() == 3 {
            return Some((parts[1].into(), parts[2].into()));
        }
    }
    None
}

use crate::models::{ModelKind, model_path};
use crate::Engine;

pub struct ModelManager {
    current: Option<ModelKind>,
    engine: Option<Engine>,
}

impl ModelManager {
    pub fn new() -> Self {
        Self { current: None, engine: None }
    }

    pub fn load(&mut self, kind: ModelKind) {
        if self.current == Some(kind) {
            return;
        }

        // Unload existing to save RAM before loading new
        self.engine = None; 
        let path = model_path(kind);

        // n_threads determined by safety.rs
        if let Ok(e) = Engine::new(path, 4) {
            self.engine = Some(e);
            self.current = Some(kind);
        }
    }

    pub fn engine_mut(&mut self) -> Option<&mut Engine> {
        self.engine.as_mut()
    }
}

// Conceptual hardware awareness logic
pub fn safe_threads() -> i32 {
    // In a real native environment, use sysinfo or similar
    // 8-core CPU -> 4 threads is usually ideal for performance/thermal balance
    let cores = 8; 

    if cores <= 4 { 2 }
    else if cores <= 6 { 3 }
    else { 4 }
}

pub fn check_thermal_throttle() -> bool {
    // Return true if device temperature > 45C
    false
}

