import React, { useState, useEffect, useRef } from 'react';
import { 
  ChatSession, Message, LocalModel, 
  AppConfig, DeviceStats, ReasoningStep, PerformanceMode, TaskType, MemoryEntry
} from './types';
import { AVAILABLE_MODELS, DEFAULT_CONFIG, STORAGE_KEYS, APP_NAME } from './constants';
import { storageService } from './services/storageService';
import { localInference } from './services/localInference';
import { initLLM } from './native/LocalLLM';
import { 
  SendIcon, MenuIcon, PlusIcon, SettingsIcon, 
  TrashIcon, BotIcon, MicIcon, SpeakerIcon
} from './components/Icons';
import { MemoryPanel } from './app/components/MemoryPanel';
import { SplashScreen } from './components/SplashScreen';
import { AnimatedLogo } from './components/AnimatedLogo';

const App: React.FC = () => {
  const [booting, setBooting] = useState(true);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [deviceStats, setDeviceStats] = useState<DeviceStats>({ 
    ramUsage: 1.2, totalRam: 12, temp: 34, npuLoad: 4, batteryLevel: 98 
  });
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [activeSteps, setActiveSteps] = useState<ReasoningStep[]>([]);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showMemory, setShowMemory] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [memories, setMemories] = useState<MemoryEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    initLLM("/data/data/com.nexus/models/qwen2.5-coder-7b.gguf");
    const loaded = storageService.loadSessions();
    if (loaded.length > 0) {
      setSessions(loaded);
      setCurrentSessionId(loaded[0].id);
    } else createNewSession();

    const loadedConfig = storageService.loadConfig();
    if (loadedConfig) setConfig(loadedConfig);

    const loadedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
    if (loadedMemories) setMemories(JSON.parse(loadedMemories));
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      const multiplier = config.profile === 'Performance' ? 1.5 : config.profile === 'Eco' ? 0.5 : 1;
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (isStreaming ? 0.4 * multiplier : -0.1)).toFixed(2),
        temp: isStreaming ? Math.min(prev.temp + 0.5 * multiplier, 55) : Math.max(prev.temp - 0.2, 30),
        npuLoad: isStreaming ? 75 * multiplier : 2,
        batteryLevel: Math.max(0, prev.batteryLevel - (isStreaming ? 0.03 * multiplier : 0.001))
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isStreaming, config.profile]);

  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);
  useEffect(() => { storageService.saveConfig(config); }, [config]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming, activeSteps]);

  const createNewSession = () => {
    const s: ChatSession = {
      id: Date.now().toString(),
      title: 'Nexus Node Alpha',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [s, ...prev]);
    setCurrentSessionId(s.id);
    setShowSidebar(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const taskType = localInference.classifyTask(input);
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: input, 
      timestamp: Date.now(),
      taskType
    };

    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s, messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 24) : s.title
    } : s));

    setInput('');
    setIsStreaming(true);
    setActiveSteps([]);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now(), reasoningSteps: [] };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (newSteps) => setActiveSteps(newSteps),
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full, sources, toolCalls) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => s.id === currentSessionId ? {
          ...s, messages: s.messages.map(m => m.id === assistantId ? { ...m, sources, toolCalls, reasoningSteps: [], isPersonalized: sources.length > 0 } : m)
        } : s));

        const updatedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
        if (updatedMemories) setMemories(JSON.parse(updatedMemories));

        if (config.voiceEnabled) speak(full);
      },
      (err) => { setIsStreaming(false); console.error(err); }
    );
  };

  const deleteMemory = (id: string) => {
    const updated = memories.filter(m => m.id !== id);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const pinMemory = (id: string) => {
    const updated = memories.map(m => m.id === id ? { ...m, isPinned: !m.isPinned } : m);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const toggleListening = () => {
    if (isListening) setIsListening(false);
    else {
      setIsListening(true);
      setTimeout(() => {
        if (isListening) setInput("Analyze my Nexus workspace.");
        setIsListening(false);
      }, 1500);
    }
  };

  const speak = (text: string) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text.slice(0, 150));
      window.speechSynthesis.speak(utterance);
    }
  };

  const renderContent = (content: string) => {
    const blocks = content.split(/(\n\n|```[\s\S]*?```)/g);
    return blocks.map((block, i) => {
      const trimmed = block.trim();
      if (!trimmed) return null;
      if (trimmed.startsWith('```')) {
        const lines = trimmed.split('\n');
        const lang = lines[0].replace('```', '').trim() || 'code';
        const code = lines.slice(1, -1).join('\n');
        return (
          <div key={i} className="my-2 rounded-lg overflow-hidden border border-white/10 bg-[#0a0a0f] font-mono shadow-sm">
             <div className="bg-[#1a1a24] px-2.5 py-1 flex items-center justify-between border-b border-white/5">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">{lang}</span>
                <button onClick={() => navigator.clipboard.writeText(code)} className="text-[8px] text-indigo-400 font-bold uppercase">Copy</button>
             </div>
             <div className="p-2.5 overflow-x-auto no-scrollbar">
                <pre className="text-[10.5px] leading-relaxed text-indigo-300/90 whitespace-pre">{code}</pre>
             </div>
          </div>
        );
      }
      return <p key={i} className="mb-2.5 last:mb-0 leading-[1.55] font-medium text-[12px] text-slate-200 whitespace-pre-wrap">{trimmed}</p>;
    });
  };

  if (booting) {
    return <SplashScreen duration={4500} onFinish={() => setBooting(false)} />;
  }

  return (
    <div className="flex h-full w-full max-w-md mx-auto bg-[#07070a] text-slate-100 overflow-hidden relative font-sans animate-in fade-in duration-1000">

      {/* Sidebar Navigation */}
      {(showSidebar || showMemory) && <div className="fixed inset-0 bg-black/95 z-40 backdrop-blur-md" onClick={() => { setShowSidebar(false); setShowMemory(false); }} />}

      <aside className={`fixed left-0 top-0 h-full w-64 bg-[#0d0d14] z-50 transform transition-transform duration-500 cubic-bezier(0.4, 0, 0.2, 1) ${showSidebar ? 'translate-x-0' : '-translate-x-full'} border-r border-white/5`}>
        <div className="p-5 flex flex-col h-full">
          <div className="flex items-center gap-2 mb-8">
            <AnimatedLogo className="w-8 h-8" />
            <div className="flex flex-col">
               <h2 className="text-sm font-black tracking-tighter italic text-white uppercase leading-none">{APP_NAME}</h2>
               <span className="text-[7px] font-black text-slate-500 tracking-[0.1em] mt-0.5 uppercase">v4.1.0 Cinematic</span>
            </div>
          </div>

          <button onClick={createNewSession} className="flex items-center justify-center gap-2 w-full p-3 mb-6 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-black shadow-lg shadow-indigo-600/30 active:scale-[0.98] transition-all text-xs">
            <PlusIcon className="w-3.5 h-3.5" /> Initialize Nexus Link
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-3">
            <h3 className="text-[8px] font-black text-slate-500 uppercase tracking-widest px-1 mb-1">Nexus Nodes</h3>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all border ${currentSessionId === s.id ? 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20' : 'hover:bg-white/5 border-transparent'}`}>
                <span className="truncate flex-1 text-[11px] font-bold tracking-tight">{s.title || 'Untitled'}</span>
                <TrashIcon className="w-3 h-3 opacity-0 group-hover:opacity-100 text-slate-500 hover:text-red-500" onClick={(e) => { e.stopPropagation(); setSessions(prev => prev.filter(x => x.id !== s.id)); }} />
              </div>
            ))}
          </div>

          <div className="mt-auto space-y-2 pt-5 border-t border-white/5">
            <button onClick={() => { setShowMemory(true); setShowSidebar(false); }} className="flex items-center gap-3 p-3 w-full rounded-xl hover:bg-white/5 transition-colors">
              <BotIcon className="w-4 h-4 text-slate-500" /> <span className="text-[11px] font-black uppercase tracking-tight text-slate-400">Memory Vault</span>
            </button>
            <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-3 p-3 w-full rounded-xl hover:bg-white/5 transition-colors">
              <SettingsIcon className="w-4 h-4 text-slate-500" /> <span className="text-[11px] font-black uppercase tracking-tight text-slate-400">Core Matrix</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Memory Panel overlay */}
      <aside className={`fixed left-0 top-0 h-full w-72 bg-[#0d0d14] z-[60] transform transition-transform duration-500 ${showMemory ? 'translate-x-0' : '-translate-x-full'} border-r border-white/5`}>
        <MemoryPanel memories={memories} onDelete={deleteMemory} onPin={pinMemory} onClose={() => setShowMemory(false)} />
      </aside>

      {/* Main Experience */}
      <main className="flex flex-col flex-1 h-full w-full relative">
        <header className="px-4 py-3 border-b border-white/5 bg-[#07070a]/95 backdrop-blur-3xl sticky top-0 z-30 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={() => setShowSidebar(true)} className="p-1.5 -ml-1 hover:bg-white/5 rounded-xl"><MenuIcon className="w-5 h-5 text-slate-400" /></button>
            <div className="flex flex-col">
              <h1 className="text-[11px] font-black tracking-tight text-white uppercase truncate max-w-[100px]">{currentSession?.title || APP_NAME}</h1>
              <div className="flex items-center gap-1 mt-0.5">
                 <span className={`w-1 h-1 rounded-full ${deviceStats.temp > 50 ? 'bg-amber-500' : 'bg-cyan-500 animate-pulse'} shadow-[0_0_5px_rgba(34,211,238,0.5)]`} />
                 <span className="text-[8px] font-black text-slate-500 tracking-tighter uppercase">{config.profile} Matrix</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2">
             <div className="text-right flex flex-col items-end mr-1">
                <span className="text-[6px] font-black text-slate-500 uppercase tracking-widest">TPS</span>
                <span className="text-[9px] font-black text-indigo-400 tabular-nums">{isStreaming ? currentTps : '0.0'}</span>
             </div>
             <button onClick={() => setShowSettings(true)} className="p-1.5 hover:bg-white/5 rounded-xl"><SettingsIcon className="w-4 h-4 text-slate-500" /></button>
          </div>
        </header>

        {/* Chat Feed */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-8 no-scrollbar pb-36 scroll-smooth">
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-6 py-10 animate-in zoom-in-95 duration-1000">
