type TokenCallback = (token: string) => void;

export function initLLM(modelPath: string) {
  LocalLLM.initEngine(modelPath, 4);
}

export function generateStream(
  prompt: string,
  onToken: TokenCallback
) {
  LocalLLM.generate(prompt, onToken);
}

