import React, { useEffect } from "react";
import { View, Image, StyleSheet } from "react-native";
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withTiming,
  Easing,
  interpolate,
  withDelay,
} from "react-native-reanimated";

type Props = {
  duration?: number;
  iconSource: any;
};

export const AnimatedLogo: React.FC<Props> = ({ duration = 3000, iconSource }) => {
  const scale = useSharedValue(0);
  const opacity = useSharedValue(0);

  useEffect(() => {
    scale.value = withTiming(1, {
      duration: duration,
      easing: Easing.out(Easing.exp),
    });

    opacity.value = withDelay(
      duration * 0.2,
      withTiming(1, { duration: duration * 0.5 })
    );
  }, []);

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [{ scale: scale.value }],
      opacity: opacity.value,
    };
  });

  return (
    <View style={styles.container}>
      <Animated.Image source={iconSource} style={[styles.logo, animatedStyle]} />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: "#0B0B0B", // glossy black background
    justifyContent: "center",
    alignItems: "center",
  },
  logo: {
    width: 180,
    height: 180,
    tintColor: undefined,
    resizeMode: "contain",
  },
});

