              placeholder={isStreaming ? "Nexus processing..." : "Neural prompt link..."}
              disabled={isStreaming}
              className="flex-1 bg-transparent border-none focus:ring-0 text-[12px] p-1.5 no-scrollbar resize-none max-h-32 min-h-[36px] placeholder:text-slate-700 font-bold text-white"
              rows={1}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
            />
            <button onClick={handleSend} disabled={!input.trim() || isStreaming} className={`p-2.5 rounded-xl transition-all flex items-center justify-center ${!input.trim() || isStreaming ? 'bg-white/5 text-slate-700' : 'bg-indigo-600 text-white shadow-indigo-600/20'}`}>
              <SendIcon className="w-4.5 h-4.5" />
            </button>
          </div>
        </div>
      </main>

      {/* Settings Overlay */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={() => setShowSettings(false)} />
          <div className="relative bg-[#0d0d14] w-full max-w-sm rounded-t-[2.5rem] sm:rounded-[2.5rem] p-8 space-y-8 border-t border-white/5 animate-in slide-in-from-bottom-32 duration-500">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-black tracking-tighter text-white uppercase italic tracking-tight">Nexus Core Matrix</h2>
              <button onClick={() => setShowSettings(false)} className="w-8 h-8 flex items-center justify-center bg-white/5 rounded-full text-slate-500 font-black">×</button>
            </div>
            <div className="space-y-6">
              <div className="space-y-3">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest px-0.5">Active Neural Model</label>
                <div className="space-y-2">
                  {AVAILABLE_MODELS.map(m => (
                    <div key={m.id} onClick={() => setConfig({ ...config, activeModelId: m.id })} className={`p-4 rounded-xl border-2 transition-all cursor-pointer ${config.activeModelId === m.id ? 'border-indigo-600 bg-indigo-600/10' : 'border-white/5 bg-white/[0.02]'}`}>
                      <div className="flex justify-between items-center mb-1">
                        <span className="text-[12px] font-black text-white">{m.name}</span>
                        <span className="text-[7px] font-black bg-indigo-600/20 text-indigo-400 px-1.5 py-0.5 rounded uppercase">{m.version}</span>
                      </div>
                      <p className="text-[8px] text-slate-600 font-bold leading-relaxed">{m.description}</p>
                    </div>
                  ))}
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-2">
                   <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Power Governor</label>
                   <div className="grid grid-cols-3 bg-white/5 p-1 rounded-xl border border-white/5">
                     {(['Eco', 'Balanced', 'Performance'] as PerformanceMode[]).map(p => (
                       <button key={p} onClick={() => setConfig({...config, profile: p})} className={`py-2 text-[8px] font-black rounded-lg transition-all ${config.profile === p ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}>{p[0]}</button>
                     ))}
                   </div>
                 </div>
                 <div className="space-y-2">
                   <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Cognitive Sync</label>
                   <div onClick={() => setConfig({ ...config, useCognitiveMemory: !config.useCognitiveMemory })} className={`w-full py-2.5 rounded-xl text-[9px] font-black text-center cursor-pointer transition-all border-2 flex items-center justify-center gap-2 ${config.useCognitiveMemory ? 'border-indigo-600 bg-indigo-600/10 text-indigo-400' : 'border-white/5 text-slate-500'}`}>
                     <div className={`w-1.5 h-1.5 rounded-full ${config.useCognitiveMemory ? 'bg-indigo-500 shadow-[0_0_5px_indigo]' : 'bg-slate-700'}`} />
                     {config.useCognitiveMemory ? 'Active' : 'Offline'}
                   </div>
                 </div>
              </div>
            </div>
            <button onClick={() => setShowSettings(false)} className="w-full py-4 bg-white text-black rounded-2xl font-black text-xs uppercase tracking-tight transition-transform active:scale-95">Commit Nexus Config</button>
          </div>
        </div>
      )}
    </div>
  );
};

