import React, { useEffect, useState, useMemo } from 'react';
import { AnimatedLogo } from './AnimatedLogo';
import { APP_NAME, TAGLINE } from '../constants';

interface SplashScreenProps {
  duration: number;
  onFinish: () => void;
}

export const SplashScreen: React.FC<SplashScreenProps> = ({ duration, onFinish }) => {
  const [stage, setStage] = useState<'converge' | 'form' | 'reveal' | 'ready' | 'exit'>('converge');

  // Generate deterministic particles for cinematic convergence (from edges to center)
  const particles = useMemo(() => {
    return Array.from({ length: 80 }).map((_, i) => {
      // Start position: Randomly on the edge or outside
      const angle = Math.random() * Math.PI * 2;
      const radius = 150 + Math.random() * 50; // Outside viewport percentage
      return {
        id: i,
        startX: Math.cos(angle) * radius,
        startY: Math.sin(angle) * radius,
        delay: Math.random() * 600,
        size: Math.random() * 4 + 1,
        color: i % 2 === 0 ? '#22d3ee' : '#8b5cf6'
      };
    });
  }, []);

  useEffect(() => {
    // Cinematic sequence timing
    const tForm = setTimeout(() => setStage('form'), 1000);
    const tReveal = setTimeout(() => setStage('reveal'), 2000);
    const tReady = setTimeout(() => setStage('ready'), 3200);
    const tExit = setTimeout(() => setStage('exit'), duration - 800);
    const tFinish = setTimeout(onFinish, duration);

    return () => {
      [tForm, tReveal, tReady, tExit, tFinish].forEach(clearTimeout);
    };
  }, [duration, onFinish]);

  return (
    <div className={`fixed inset-0 z-[9999] bg-[#0B0B0B] flex flex-col items-center justify-center transition-all duration-1000 overflow-hidden ${stage === 'exit' ? 'opacity-0 scale-110 blur-xl' : 'opacity-100 scale-100 blur-0'}`}>

      {/* Particle Convergence Layer */}
      <div className="absolute inset-0 pointer-events-none">
        {particles.map((p) => (
          <div 
            key={p.id}
            className={`absolute w-1 h-1 rounded-full transition-all duration-[1200ms] cubic-bezier(0.19, 1, 0.22, 1)`}
            style={{
              top: `calc(50% + ${stage === 'converge' ? p.startY : 0}%)`,
              left: `calc(50% + ${stage === 'converge' ? p.startX : 0}%)`,
              opacity: stage === 'converge' ? 0.8 : 0,
              backgroundColor: p.color,
              transform: stage === 'converge' ? `scale(1)` : `scale(0)`,
              transitionDelay: `${p.delay}ms`,
              boxShadow: `0 0 10px ${p.color}`,
              filter: 'blur(1px)'
            }}
          />
        ))}
      </div>

      {/* Main Branding Experience */}
      <div className="relative flex flex-col items-center justify-center z-10">

        {/* Animated Logo Container */}
        <div className={`transition-all duration-[1400ms] cubic-bezier(0.34, 1.56, 0.64, 1) ${
          stage === 'converge' ? 'scale-0 opacity-0 rotate-[-120deg] blur-2xl' : 'scale-100 opacity-100 rotate-0 blur-0'
        }`}>
          <AnimatedLogo className="w-52 h-52 mb-14" animated={stage !== 'exit'} />
        </div>

        {/* Cinematic Typography Reveal */}
        <div className="flex flex-col items-center overflow-hidden">
          <div className="relative">
            <h1 className={`text-6xl font-black tracking-[0.4em] text-white italic transition-all duration-1200 cubic-bezier(0.23, 1, 0.32, 1) ${
              stage === 'reveal' || stage === 'ready' || stage === 'exit' 
                ? 'opacity-100 translate-y-0' 
                : 'opacity-0 translate-y-16'
            }`}>
              <span className="text-transparent bg-clip-text bg-gradient-to-br from-white via-cyan-300 to-blue-500 drop-shadow-[0_0_20px_rgba(34,211,238,0.5)]">
                {APP_NAME}
              </span>
            </h1>

            {/* Glossy Scanning Shine on Text */}
            <div className={`absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent -translate-x-full ${
              stage === 'reveal' ? 'animate-[nexus-shine_2s_ease-in-out_forwards]' : 'hidden'
            }`} />
          </div>

          <div className={`mt-8 h-[3px] bg-gradient-to-r from-transparent via-cyan-400 to-transparent transition-all duration-[2000ms] ${
            stage === 'reveal' || stage === 'ready' || stage === 'exit' ? 'w-64 opacity-100' : 'w-0 opacity-0'
          }`}>
             <div className="absolute top-0 left-0 w-full h-full bg-cyan-400 blur-[6px] opacity-40 animate-pulse" />
          </div>

          <p className={`mt-10 text-[12px] font-black text-slate-400 uppercase tracking-[0.7em] transition-all duration-1000 delay-500 ${
            stage === 'ready' || stage === 'exit' ? 'opacity-80 translate-y-0' : 'opacity-0 translate-y-8'
          }`}>
            {TAGLINE}
          </p>
        </div>
      </div>

      {/* Ambient Environmental Lighting */}
      {/* 1. Deep Edge Vignette */}
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.95)_100%)]" />

      {/* 2. Cyberpunk Scanlines */}
      <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.1)_50%),linear-gradient(90deg,rgba(255,0,0,0.01),rgba(0,255,0,0.01),rgba(0,0,255,0.01))] bg-[length:100%_4px,3px_100%] z-[60] opacity-40" />

      {/* 3. Flash on "Form" Stage */}
      <div className={`absolute inset-0 bg-white pointer-events-none transition-opacity duration-1000 ${
        stage === 'form' ? 'opacity-10' : 'opacity-0'
      }`} />

      {/* 4. Bottom Glow Orb */}
      <div className={`absolute bottom-[-10%] left-1/2 -translate-x-1/2 w-[120%] h-[40%] bg-indigo-500/10 rounded-full blur-[120px] transition-opacity duration-2000 ${
        stage !== 'converge' ? 'opacity-100' : 'opacity-0'
      }`} />

      <style>{`
        @keyframes nexus-shine {
          0% { transform: translateX(-100%) skewX(-20deg); }
          100% { transform: translateX(200%) skewX(-20deg); }
        }
        .cubic-bezier-nexus {
          transition-timing-function: cubic-bezier(0.19, 1, 0.22, 1);
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ChatSession, Message, LocalModel, 
  AppConfig, DeviceStats, ReasoningStep, PerformanceMode, TaskType, MemoryEntry
} from './types';
import { AVAILABLE_MODELS, DEFAULT_CONFIG, STORAGE_KEYS, APP_NAME } from './constants';
import { storageService } from './services/storageService';
import { localInference } from './services/localInference';
import { initLLM } from './native/LocalLLM';
import { 
  SendIcon, MenuIcon, PlusIcon, SettingsIcon, 
  TrashIcon, BotIcon, MicIcon, SpeakerIcon
} from './components/Icons';
import { MemoryPanel } from './app/components/MemoryPanel';
import { SplashScreen } from './components/SplashScreen';
import { AnimatedLogo } from './components/AnimatedLogo';

const App: React.FC = () => {
  const [booting, setBooting] = useState(true);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [deviceStats, setDeviceStats] = useState<DeviceStats>({ 
    ramUsage: 1.2, totalRam: 12, temp: 34, npuLoad: 4, batteryLevel: 98 
  });
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [activeSteps, setActiveSteps] = useState<ReasoningStep[]>([]);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showMemory, setShowMemory] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [memories, setMemories] = useState<MemoryEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    initLLM("/data/data/com.nexus/models/qwen2.5-coder-7b.gguf");
    const loaded = storageService.loadSessions();
    if (loaded.length > 0) {
      setSessions(loaded);
      setCurrentSessionId(loaded[0].id);
    } else createNewSession();

    const loadedConfig = storageService.loadConfig();
    if (loadedConfig) setConfig(loadedConfig);

    const loadedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
    if (loadedMemories) setMemories(JSON.parse(loadedMemories));
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      const multiplier = config.profile === 'Performance' ? 1.5 : config.profile === 'Eco' ? 0.5 : 1;
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (isStreaming ? 0.4 * multiplier : -0.1)).toFixed(2),
        temp: isStreaming ? Math.min(prev.temp + 0.5 * multiplier, 55) : Math.max(prev.temp - 0.2, 30),
        npuLoad: isStreaming ? 75 * multiplier : 2,
        batteryLevel: Math.max(0, prev.batteryLevel - (isStreaming ? 0.03 * multiplier : 0.001))
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isStreaming, config.profile]);

  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);
  useEffect(() => { storageService.saveConfig(config); }, [config]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming, activeSteps]);

  const createNewSession = () => {
    const s: ChatSession = {
      id: Date.now().toString(),
      title: 'Nexus Node Alpha',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [s, ...prev]);
    setCurrentSessionId(s.id);
    setShowSidebar(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const taskType = localInference.classifyTask(input);
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: input, 
      timestamp: Date.now(),
      taskType
    };

    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s, messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 24) : s.title
    } : s));

    setInput('');
    setIsStreaming(true);
    setActiveSteps([]);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now(), reasoningSteps: [] };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (newSteps) => setActiveSteps(newSteps),
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full, sources, toolCalls) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => s.id === currentSessionId ? {
          ...s, messages: s.messages.map(m => m.id === assistantId ? { ...m, sources, toolCalls, reasoningSteps: [], isPersonalized: sources.length > 0 } : m)
        } : s));

        const updatedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
        if (updatedMemories) setMemories(JSON.parse(updatedMemories));

        if (config.voiceEnabled) speak(full);
      },
      (err) => { setIsStreaming(false); console.error(err); }
    );
  };

  const deleteMemory = (id: string) => {
    const updated = memories.filter(m => m.id !== id);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const pinMemory = (id: string) => {
    const updated = memories.map(m => m.id === id ? { ...m, isPinned: !m.isPinned } : m);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const toggleListening = () => {
    if (isListening) setIsListening(false);
    else {
      setIsListening(true);
      setTimeout(() => {
        if (isListening) setInput("Analyze my Nexus workspace.");
        setIsListening(false);
      }, 1500);
    }
  };

  const speak = (text: string) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text.slice(0, 150));
      window.speechSynthesis.speak(utterance);
    }
  };

  const renderContent = (content: string) => {
    const blocks = content.split(/(\n\n|```[\s\S]*?```)/g);
    return blocks.map((block, i) => {
      const trimmed = block.trim();
      if (!trimmed) return null;
      if (trimmed.startsWith('```')) {
        const lines = trimmed.split('\n');
        const lang = lines[0].replace('```', '').trim() || 'code';
        const code = lines.slice(1, -1).join('\n');
        return (
          <div key={i} className="my-3 rounded-2xl overflow-hidden border border-white/10 bg-black/40 backdrop-blur-md font-mono shadow-xl">
             <div className="bg-white/5 px-4 py-2 flex items-center justify-between border-b border-white/5">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{lang}</span>
                <button onClick={() => navigator.clipboard.writeText(code)} className="text-[9px] text-cyan-400 font-black uppercase hover:text-white transition-colors">Copy Node</button>
             </div>
             <div className="p-4 overflow-x-auto no-scrollbar">
                <pre className="text-[11px] leading-relaxed text-cyan-50/90 whitespace-pre">{code}</pre>
             </div>
          </div>
        );
      }
      return <p key={i} className="mb-4 last:mb-0 leading-[1.6] font-medium text-[13px] text-slate-200 whitespace-pre-wrap">{trimmed}</p>;
    });
  };

  if (booting) {
    return <SplashScreen duration={5500} onFinish={() => setBooting(false)} />;
  }

  return (
    <div className="flex h-full w-full max-w-md mx-auto bg-[#07070a] text-slate-100 overflow-hidden relative font-sans animate-in fade-in slide-in-from-bottom-4 duration-1000">

      {/* Background Cinematic Atmosphere */}
      <div className="absolute inset-0 pointer-events-none opacity-20">
         <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-blue-600 rounded-full blur-[140px]" />
         <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-purple-600 rounded-full blur-[140px]" />
      </div>

      {/* Sidebar Navigation */}
      {(showSidebar || showMemory) && <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-40" onClick={() => { setShowSidebar(false); setShowMemory(false); }} />}

      <aside className={`fixed left-0 top-0 h-full w-72 bg-[#0d0d14]/95 backdrop-blur-2xl z-50 transform transition-transform duration-500 cubic-bezier(0.19, 1, 0.22, 1) ${showSidebar ? 'translate-x-0' : '-translate-x-full'} border-r border-white/10 shadow-[20px_0_40px_rgba(0,0,0,0.5)]`}>
        <div className="p-6 flex flex-col h-full">
          <div className="flex items-center gap-3 mb-10">
            <AnimatedLogo className="w-10 h-10" />
            <div className="flex flex-col">
               <h2 className="text-md font-black tracking-tighter italic text-white uppercase leading-none">{APP_NAME}</h2>
               <span className="text-[8px] font-black text-slate-500 tracking-[0.2em] mt-1 uppercase">Neural Core v4.3</span>
            </div>
          </div>

          <button onClick={createNewSession} className="flex items-center justify-center gap-3 w-full p-4 mb-8 bg-gradient-to-r from-indigo-600 to-blue-600 hover:from-indigo-500 hover:to-blue-500 text-white rounded-2xl font-black shadow-xl shadow-indigo-600/20 active:scale-[0.96] transition-all text-xs uppercase tracking-widest">
            <PlusIcon className="w-4 h-4" /> Link New Node
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-4">
            <h3 className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em] px-1 mb-2">Neural Workspace</h3>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-all border ${currentSessionId === s.id ? 'bg-indigo-600/15 text-indigo-400 border-indigo-500/30' : 'hover:bg-white/5 border-transparent'}`}>
                <span className="truncate flex-1 text-[12px] font-bold tracking-tight">{s.title || 'Nexus Stream'}</span>
                <TrashIcon className="w-3.5 h-3.5 opacity-0 group-hover:opacity-100 text-slate-500 hover:text-red-500 transition-opacity" onClick={(e) => { e.stopPropagation(); setSessions(prev => prev.filter(x => x.id !== s.id)); }} />
              </div>
            ))}
          </div>

          <div className="mt-auto space-y-3 pt-6 border-t border-white/5">
            <button onClick={() => { setShowMemory(true); setShowSidebar(false); }} className="flex items-center gap-4 p-4 w-full rounded-2xl hover:bg-white/5 transition-colors group">
              <BotIcon className="w-5 h-5 text-slate-500 group-hover:text-cyan-400 transition-colors" /> <span className="text-[12px] font-black uppercase tracking-widest text-slate-400 group-hover:text-white transition-colors">Cognitive Vault</span>
            </button>
            <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-4 p-4 w-full rounded-2xl hover:bg-white/5 transition-colors group">
              <SettingsIcon className="w-5 h-5 text-slate-500 group-hover:text-indigo-400 transition-colors" /> <span className="text-[12px] font-black uppercase tracking-widest text-slate-400 group-hover:text-white transition-colors">Core Matrix</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Memory Panel overlay */}
      <aside className={`fixed left-0 top-0 h-full w-80 bg-[#0d0d14]/98 backdrop-blur-3xl z-[60] transform transition-transform duration-500 cubic-bezier(0.19, 1, 0.22, 1) ${showMemory ? 'translate-x-0' : '-translate-x-full'} border-r border-white/10`}>
        <MemoryPanel memories={memories} onDelete={deleteMemory} onPin={pinMemory} onClose={() => setShowMemory(false)} />
      </aside>

      {/* Main Experience */}
      <main className="flex flex-col flex-1 h-full w-full relative z-10">
        <header className="px-5 py-4 border-b border-white/10 bg-[#07070a]/70 backdrop-blur-xl sticky top-0 z-30 flex items-center justify-between shadow-[0_4px_30px_rgba(0,0,0,0.3)]">
          <div className="flex items-center gap-4">
            <button onClick={() => setShowSidebar(true)} className="p-2 -ml-2 hover:bg-white/10 rounded-2xl transition-colors"><MenuIcon className="w-6 h-6 text-slate-300" /></button>
            <div className="flex flex-col">
              <h1 className="text-[12px] font-black tracking-widest text-white uppercase truncate max-w-[140px] italic">{currentSession?.title || 'NEXUS ALPHA'}</h1>
              <div className="flex items-center gap-1.5 mt-1">
                 <span className={`w-1.5 h-1.5 rounded-full ${deviceStats.temp > 50 ? 'bg-amber-500' : 'bg-cyan-500 animate-pulse'} shadow-[0_0_8px_rgba(34,211,238,0.6)]`} />
                 <span className="text-[9px] font-black text-slate-500 tracking-widest uppercase">{config.profile} Matrix</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <div className="text-right flex flex-col items-end mr-2">
                <span className="text-[7px] font-black text-slate-500 uppercase tracking-widest">Neural TPS</span>
                <span className="text-[11px] font-black text-cyan-400 tabular-nums">{isStreaming ? currentTps : '0.0'}</span>
             </div>
             <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-white/10 rounded-2xl transition-colors"><SettingsIcon className="w-5 h-5 text-slate-400" /></button>
          </div>
        </header>

        {/* Chat Feed */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto px-5 py-6 space-y-10 no-scrollbar pb-40 scroll-smooth">
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-10 py-12 animate-in zoom-in-95 duration-1000">
              <div className="relative">
                <AnimatedLogo className="w-24 h-24" />
                <div className="absolute inset-0 bg-cyan-500/10 blur-[50px] rounded-full animate-pulse" />
              </div>
              <div className="space-y-3">
                <h2 className="text-2xl font-black tracking-[0.2em] text-white uppercase italic drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]">{APP_NAME}</h2>
                <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest leading-relaxed max-w-[280px]">Autonomous Identity Agent | local ARM64 Inference | Cinematic UX</p>
              </div>
              <div className="flex flex-col gap-3 w-full max-w-[260px]">
                {['Optimize Workspace Code', 'Analyze Neural Identity', 'Generate Logic Flow'].map(h => (
                  <button key={h} onClick={() => setInput(h)} className="p-4 bg-white/5 backdrop-blur-md border border-white/5 rounded-2xl text-[11px] font-black text-slate-400 hover:text-cyan-400 hover:border-cyan-500/30 transition-all text-left flex items-center justify-between active:scale-[0.97] group">
                    {h} <PlusIcon className="w-4 h-4 text-indigo-500 group-hover:scale-125 transition-transform" />
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentSession?.messages.map(m => (
            <div key={m.id} className={`flex w-full ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in duration-500`}>
              <div className={`flex flex-col gap-3 max-w-[96%] ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                {m.role === 'user' && m.taskType && (
                  <span className="text-[8px] font-black uppercase tracking-[0.2em] bg-indigo-600/10 text-indigo-400 px-2.5 py-1 rounded-full border border-indigo-500/20">{m.taskType} NODE</span>
                )}

                {m.role === 'assistant' && activeSteps.length > 0 && m.id === currentSession?.messages[currentSession?.messages.length - 1].id && (
                  <div className="flex flex-wrap gap-2 mb-2">
                    {activeSteps.map((s, idx) => (
                      <div key={idx} className={`flex items-center gap-2 px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest border transition-all duration-300 ${
                        s.status === 'active' ? 'bg-cyan-600 text-white border-cyan-400 shadow-[0_0_12px_rgba(8,145,178,0.5)] animate-pulse' : 
                        s.status === 'complete' ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/30' : 
                        'bg-white/5 text-slate-600 border-transparent opacity-40'
                      }`}>
                        {s.label}
                      </div>
                    ))}
                  </div>
                )}

                <div className={`p-5 rounded-[2rem] text-[13.5px] leading-[1.6] shadow-2xl transition-all duration-500 ${
                  m.role === 'user' 
                    ? 'bg-gradient-to-br from-indigo-600 to-blue-700 text-white rounded-tr-none font-bold' 
                    : 'bg-[#12121c]/80 backdrop-blur-xl text-slate-200 rounded-tl-none border border-white/10'
                }`}>
                  {renderContent(m.content || '')}
                  {isStreaming && !m.content && m.role === 'assistant' && (
                    <div className="flex gap-2 py-2"><div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce" /><div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.2s]" /><div className="w-1.5 h-1.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.4s]" /></div>
                  )}
                </div>

                {m.toolCalls && m.toolCalls.length > 0 && (
                  <div className="mt-2 w-full flex flex-col gap-3">
                    {m.toolCalls.map((tc, idx) => (
                      <div key={idx} className="bg-cyan-600/5 border border-cyan-500/20 p-4 rounded-3xl backdrop-blur-sm animate-in zoom-in-95 duration-300">
                        <div className="flex items-center justify-between mb-2">
                          <span className="text-[9px] font-black text-cyan-400 uppercase tracking-[0.2em]">Matrix Exec: {tc.name}</span>
                          <span className="text-[8px] font-black text-emerald-500 uppercase bg-emerald-500/10 px-2 py-0.5 rounded-full">Resolved</span>
                        </div>
                        <p className="text-[10px] font-bold text-slate-400 italic leading-relaxed">System Response: {tc.result}</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>

        {/* Cinematic Input Bar */}
        <div className="absolute bottom-0 left-0 right-0 p-5 bg-gradient-to-t from-[#07070a] via-[#07070a]/90 to-transparent z-40">
          <div className="bg-[#1a1a26]/80 backdrop-blur-2xl p-3 rounded-[2rem] border border-white/10 shadow-[0_-10px_50px_rgba(0,0,0,0.5)] flex items-end gap-3 focus-within:ring-2 ring-indigo-500/40 transition-all duration-500">
            <button onClick={toggleListening} className={`p-3 rounded-full transition-all duration-300 ${isListening ? 'bg-red-500 text-white shadow-[0_0_15px_rgba(239,68,68,0.5)]' : 'hover:bg-white/10 text-slate-400'}`}>
              <MicIcon className="w-5 h-5" active={isListening} />
            </button>
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isStreaming ? "Neural process active..." : "Initiate neural link..."}
              disabled={isStreaming}
              className="flex-1 bg-transparent border-none focus:ring-0 text-[13px] p-2 no-scrollbar resize-none max-h-32 min-h-[40px] placeholder:text-slate-600 font-bold text-white transition-all"
              rows={1}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
            />
            <button onClick={handleSend} disabled={!input.trim() || isStreaming} className={`p-3.5 rounded-full transition-all duration-300 flex items-center justify-center ${!input.trim() || isStreaming ? 'bg-white/5 text-slate-700' : 'bg-gradient-to-br from-indigo-500 to-blue-600 text-white shadow-lg shadow-indigo-600/30 hover:scale-105'}`}>
              <SendIcon className="w-5 h-5" />
            </button>
          </div>
        </div>
      </main>

      {/* Settings Modal overlay */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center">
          <div className="absolute inset-0 bg-black/95 backdrop-blur-xl" onClick={() => setShowSettings(false)} />
          <div className="relative bg-[#0d0d14] w-full max-w-sm rounded-t-[3rem] sm:rounded-[3rem] p-10 space-y-10 border-t border-white/10 animate-in slide-in-from-bottom-64 duration-700 cubic-bezier(0.19, 1, 0.22, 1) shadow-2xl">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <h2 className="text-xl font-black tracking-tighter text-white uppercase italic">Neural Settings</h2>
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">System Orchestration</span>
              </div>
              <button onClick={() => setShowSettings(false)} className="w-10 h-10 flex items-center justify-center bg-white/5 rounded-full text-slate-400 hover:text-white transition-colors">×</button>
            </div>

            <div className="space-y-8">
              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] px-1">Neural Core Model</label>
                <div className="space-y-3">
                  {AVAILABLE_MODELS.map(m => (
                    <div key={m.id} onClick={() => setConfig({ ...config, activeModelId: m.id })} className={`p-5 rounded-3xl border-2 transition-all duration-300 cursor-pointer ${config.activeModelId === m.id ? 'border-cyan-500 bg-cyan-500/10 shadow-[0_0_20px_rgba(34,211,238,0.2)]' : 'border-white/5 bg-white/[0.03] hover:bg-white/[0.05]'}`}>
                      <div className="flex justify-between items-center mb-2">
                        <span className={`text-[13px] font-black ${config.activeModelId === m.id ? 'text-cyan-400' : 'text-white'}`}>{m.name}</span>
                        <span className="text-[8px] font-black bg-white/10 text-slate-400 px-2.5 py-1 rounded-full uppercase">{m.version}</span>
                      </div>
                      <p className="text-[10px] text-slate-500 font-bold leading-relaxed">{m.description}</p>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-5">
                 <div className="space-y-3">
                   <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Power Mode</label>
                   <div className="grid grid-cols-3 bg-white/5 p-1.5 rounded-2xl border border-white/5">
                     {(['Eco', 'Balanced', 'Performance'] as PerformanceMode[]).map(p => (
                       <button key={p} onClick={() => setConfig({...config, profile: p})} className={`py-3 text-[9px] font-black rounded-xl transition-all ${config.profile === p ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-slate-500 hover:text-slate-300'}`}>{p[0]}</button>
                     ))}
                   </div>
                 </div>
                 <div className="space-y-3">
                   <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Sync Vault</label>
                   <div onClick={() => setConfig({ ...config, useCognitiveMemory: !config.useCognitiveMemory })} className={`w-full py-3.5 rounded-2xl text-[10px] font-black text-center cursor-pointer transition-all border-2 flex items-center justify-center gap-3 ${config.useCognitiveMemory ? 'border-cyan-500 bg-cyan-500/10 text-cyan-400 shadow-[0_0_15px_rgba(34,211,238,0.15)]' : 'border-white/5 text-slate-600 hover:border-white/20'}`}>
                     <div className={`w-2 h-2 rounded-full ${config.useCognitiveMemory ? 'bg-cyan-400 shadow-[0_0_10px_cyan]' : 'bg-slate-700'}`} />
                     {config.useCognitiveMemory ? 'Linked' : 'Offline'}
