            <button onClick={() => setShowSettings(false)} className="w-full py-5 bg-gradient-to-r from-white to-slate-200 text-black rounded-[1.8rem] font-black text-[12px] uppercase tracking-[0.2em] shadow-2xl transition-transform active:scale-95 hover:brightness-110">Commit Neural Sync</button>
          </div>
        </div>
      )}
    </div>
  );
};

