import React, { useEffect, useState, useMemo } from 'react';
import { AnimatedLogo } from './AnimatedLogo';
import { APP_NAME, TAGLINE } from '../constants';

interface SplashScreenProps {
  duration: number;
  onFinish: () => void;
}

export const SplashScreen: React.FC<SplashScreenProps> = ({ duration, onFinish }) => {
  const [stage, setStage] = useState<'converge' | 'ignite' | 'reveal' | 'stabilize' | 'exit'>('converge');

  // Procedural particles shooting from screen edges to the center for cinematic convergence
  const particles = useMemo(() => {
    return Array.from({ length: 90 }).map((_, i) => {
      const angle = Math.random() * Math.PI * 2;
      const radius = 180 + Math.random() * 60; // Start outside the center focus
      return {
        id: i,
        startX: Math.cos(angle) * radius,
        startY: Math.sin(angle) * radius,
        delay: Math.random() * 900,
        size: Math.random() * 3.5 + 1,
        color: i % 3 === 0 ? '#22d3ee' : i % 3 === 1 ? '#8b5cf6' : '#ffffff',
        speed: 900 + Math.random() * 1100
      };
    });
  }, []);

  useEffect(() => {
    // Cinematic timeline orchestration
    const tIgnite = setTimeout(() => setStage('ignite'), 1200);
    const tReveal = setTimeout(() => setStage('reveal'), 2200);
    const tStabilize = setTimeout(() => setStage('stabilize'), 3600);
    const tExit = setTimeout(() => setStage('exit'), duration - 1000);
    const tFinish = setTimeout(onFinish, duration);

    return () => {
      [tIgnite, tReveal, tStabilize, tExit, tFinish].forEach(clearTimeout);
    };
  }, [duration, onFinish]);

  return (
    <div className={`fixed inset-0 z-[9999] bg-[#07070a] flex flex-col items-center justify-center transition-all duration-1000 cubic-bezier(0.19, 1, 0.22, 1) ${
      stage === 'exit' ? 'opacity-0 scale-125 blur-3xl' : 'opacity-100 scale-100 blur-0'
    }`}>

      {/* 60FPS Particle Convergence Layer */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        {particles.map((p) => (
          <div 
            key={p.id}
            className={`absolute w-1 h-1 rounded-full transition-all cubic-bezier(0.19, 1, 0.22, 1)`}
            style={{
              top: `calc(50% + ${stage === 'converge' ? p.startY : 0}%)`,
              left: `calc(50% + ${stage === 'converge' ? p.startX : 0}%)`,
              opacity: stage === 'converge' ? 0.8 : 0,
              backgroundColor: p.color,
              transform: stage === 'converge' ? `scale(1.5)` : `scale(0)`,
              transitionDuration: `${p.speed}ms`,
              transitionDelay: `${p.delay}ms`,
              boxShadow: `0 0 15px ${p.color}`,
              filter: 'blur(0.5px)'
            }}
          />
        ))}
      </div>

      {/* Neural Link Ignite Flash */}
      <div className={`absolute inset-0 bg-white pointer-events-none transition-opacity duration-1000 ${
        stage === 'ignite' ? 'opacity-10' : 'opacity-0'
      }`} />

      {/* Atmospheric Ground Glow */}
      <div className={`absolute bottom-[-15%] left-1/2 -translate-x-1/2 w-[160%] h-[50%] bg-cyan-500/10 rounded-full blur-[160px] transition-opacity duration-[3000ms] ${
        stage !== 'converge' ? 'opacity-100' : 'opacity-0'
      }`} />

      {/* Main Branding Experience */}
      <div className="relative flex flex-col items-center justify-center z-10">

        {/* Animated Logo Container with smooth acceleration */}
        <div className={`transition-all duration-[1600ms] cubic-bezier(0.34, 1.56, 0.64, 1) ${
          stage === 'converge' ? 'scale-0 opacity-0 rotate-[-270deg] blur-3xl' : 'scale-100 opacity-100 rotate-0 blur-0'
        }`}>
          <AnimatedLogo className="w-52 h-52 mb-16" animated={stage !== 'exit'} />
        </div>

        {/* Professional Typography Reveal System */}
        <div className="flex flex-col items-center px-6">
          <div className="relative overflow-hidden">
            <h1 className={`text-6xl font-black tracking-[0.5em] text-white italic transition-all duration-[1600ms] cubic-bezier(0.23, 1, 0.32, 1) ${
              ['reveal', 'stabilize', 'exit'].includes(stage) 
                ? 'opacity-100 translate-y-0' 
                : 'opacity-0 translate-y-24 blur-xl'
            }`}>
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-white via-cyan-200 to-indigo-400 drop-shadow-[0_0_30px_rgba(34,211,238,0.3)]">
                {APP_NAME}
              </span>
            </h1>

            {/* Cinematic Scanning Text Shine */}
            <div className={`absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent -translate-x-full ${
              stage === 'reveal' ? 'animate-[nexus-text-shine_2.5s_ease-in-out_forwards]' : 'hidden'
            }`} />
          </div>

          {/* Energy Divider Beam */}
          <div className={`mt-10 h-[2px] bg-gradient-to-r from-transparent via-cyan-400/80 to-transparent transition-all duration-[2500ms] ${
            ['reveal', 'stabilize', 'exit'].includes(stage) ? 'w-64 opacity-100' : 'w-0 opacity-0'
          }`}>
             <div className="absolute top-0 left-0 w-full h-full bg-cyan-400 blur-[5px] opacity-40 animate-pulse" />
          </div>

          <p className={`mt-12 text-[11px] font-black text-slate-400 uppercase tracking-[0.9em] transition-all duration-1200 delay-700 ${
            ['stabilize', 'exit'].includes(stage) ? 'opacity-80 translate-y-0' : 'opacity-0 translate-y-8'
          }`}>
            {TAGLINE}
          </p>
        </div>
      </div>

      {/* Environmental Textures */}
      {/* 1. Perspective Vignette */}
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.95)_100%)]" />

      {/* 2. Neural Fiber Overlay (Scanlines) */}
      <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.08)_50%),linear-gradient(90deg,rgba(255,0,0,0.01),rgba(0,255,0,0.01),rgba(34,211,238,0.02))] bg-[length:100%_4px,4px_100%] z-[60] opacity-40" />

      <style>{`
        @keyframes nexus-text-shine {
          0% { transform: translateX(-150%) skewX(-30deg); }
          100% { transform: translateX(300%) skewX(-30deg); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ChatSession, Message, LocalModel, 
  AppConfig, DeviceStats, ReasoningStep, PerformanceMode, TaskType, MemoryEntry
} from './types';
import { AVAILABLE_MODELS, DEFAULT_CONFIG, STORAGE_KEYS, APP_NAME } from './constants';
import { storageService } from './services/storageService';
import { localInference } from './services/localInference';
import { 
  SendIcon, MenuIcon, PlusIcon, SettingsIcon, 
  TrashIcon, BotIcon, MicIcon, SpeakerIcon
} from './components/Icons';
import { MemoryPanel } from './app/components/MemoryPanel';
import { SplashScreen } from './components/SplashScreen';
import { AnimatedLogo } from './components/AnimatedLogo';

const App: React.FC = () => {
  const [booting, setBooting] = useState(true);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [deviceStats, setDeviceStats] = useState<DeviceStats>({ 
    ramUsage: 1.2, totalRam: 12, temp: 34, npuLoad: 4, batteryLevel: 98 
  });
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [activeSteps, setActiveSteps] = useState<ReasoningStep[]>([]);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showMemory, setShowMemory] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [memories, setMemories] = useState<MemoryEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    // Neural Node Initialization Phase
    const loaded = storageService.loadSessions();
    if (loaded.length > 0) {
      setSessions(loaded);
      setCurrentSessionId(loaded[0].id);
    } else createNewSession();

    const loadedConfig = storageService.loadConfig();
    if (loadedConfig) setConfig(loadedConfig);

    const loadedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
    if (loadedMemories) setMemories(JSON.parse(loadedMemories));
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      const multiplier = config.profile === 'Performance' ? 1.5 : config.profile === 'Eco' ? 0.5 : 1;
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (isStreaming ? 0.4 * multiplier : -0.1)).toFixed(2),
        temp: isStreaming ? Math.min(prev.temp + 0.5 * multiplier, 55) : Math.max(prev.temp - 0.2, 30),
        npuLoad: isStreaming ? 75 * multiplier : 2,
        batteryLevel: Math.max(0, prev.batteryLevel - (isStreaming ? 0.03 * multiplier : 0.001))
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isStreaming, config.profile]);

  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);
  useEffect(() => { storageService.saveConfig(config); }, [config]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming, activeSteps]);

  const createNewSession = () => {
    const s: ChatSession = {
      id: Date.now().toString(),
      title: 'Neural Stream Alpha',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [s, ...prev]);
    setCurrentSessionId(s.id);
    setShowSidebar(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const taskType = localInference.classifyTask(input);
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: input, 
      timestamp: Date.now(),
      taskType
    };

    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s, messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 24) : s.title
    } : s));

    setInput('');
    setIsStreaming(true);
    setActiveSteps([]);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now(), reasoningSteps: [] };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (newSteps) => setActiveSteps(newSteps),
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full, sources, toolCalls) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => s.id === currentSessionId ? {
          ...s, messages: s.messages.map(m => m.id === assistantId ? { ...m, sources, toolCalls, reasoningSteps: [], isPersonalized: sources.length > 0 } : m)
        } : s));

        const updatedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
        if (updatedMemories) setMemories(JSON.parse(updatedMemories));

        if (config.voiceEnabled) speak(full);
      },
      (err) => { setIsStreaming(false); console.error(err); }
    );
  };

  const deleteMemory = (id: string) => {
    const updated = memories.filter(m => m.id !== id);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const pinMemory = (id: string) => {
    const updated = memories.map(m => m.id === id ? { ...m, isPinned: !m.isPinned } : m);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const toggleListening = () => {
    if (isListening) setIsListening(false);
    else {
      setIsListening(true);
      setTimeout(() => {
        if (isListening) setInput("Analyze my active workspace.");
        setIsListening(false);
      }, 1500);
    }
  };

  const speak = (text: string) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text.slice(0, 150));
      window.speechSynthesis.speak(utterance);
    }
  };

  const renderContent = (content: string) => {
    const blocks = content.split(/(\n\n|```[\s\S]*?```)/g);
    return blocks.map((block, i) => {
      const trimmed = block.trim();
      if (!trimmed) return null;
      if (trimmed.startsWith('```')) {
        const lines = trimmed.split('\n');
        const lang = lines[0].replace('```', '').trim() || 'code';
        const code = lines.slice(1, -1).join('\n');
        return (
          <div key={i} className="my-4 rounded-3xl overflow-hidden border border-white/10 bg-black/50 backdrop-blur-xl font-mono shadow-2xl">
             <div className="bg-white/5 px-5 py-2.5 flex items-center justify-between border-b border-white/10">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{lang} Node</span>
                <button onClick={() => navigator.clipboard.writeText(code)} className="text-[10px] text-indigo-400 font-black uppercase hover:text-white transition-colors">Neural Link</button>
             </div>
             <div className="p-5 overflow-x-auto no-scrollbar">
                <pre className="text-[11.5px] leading-relaxed text-indigo-100/90 whitespace-pre">{code}</pre>
             </div>
          </div>
        );
      }
      return <p key={i} className="mb-5 last:mb-0 leading-[1.7] font-medium text-[14px] text-slate-200 whitespace-pre-wrap">{trimmed}</p>;
    });
  };

  if (booting) {
    return <SplashScreen duration={6500} onFinish={() => setBooting(false)} />;
  }

  return (
    <div className="flex h-full w-full max-w-md mx-auto bg-[#07070a] text-slate-100 overflow-hidden relative font-sans animate-in fade-in slide-in-from-bottom-12 duration-[1800ms] cubic-bezier(0.19, 1, 0.22, 1)">

      {/* Background Neural Atmosphere */}
      <div className="absolute inset-0 pointer-events-none opacity-20">
         <div className="absolute top-[-20%] left-[-20%] w-[80%] h-[80%] bg-blue-600/30 rounded-full blur-[140px] animate-pulse" />
         <div className="absolute bottom-[-20%] right-[-20%] w-[80%] h-[80%] bg-purple-600/30 rounded-full blur-[140px] animate-pulse [animation-delay:2s]" />
      </div>

      {/* Sidebar Interface */}
      {(showSidebar || showMemory) && <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-40 transition-opacity duration-500" onClick={() => { setShowSidebar(false); setShowMemory(false); }} />}

      <aside className={`fixed left-0 top-0 h-full w-72 bg-[#0d0d14]/98 backdrop-blur-3xl z-50 transform transition-transform duration-700 cubic-bezier(0.19, 1, 0.22, 1) ${showSidebar ? 'translate-x-0' : '-translate-x-full'} border-r border-white/10 shadow-[30px_0_60px_rgba(0,0,0,0.6)]`}>
        <div className="p-7 flex flex-col h-full">
          <div className="flex items-center gap-4 mb-12">
            <AnimatedLogo className="w-12 h-12" />
            <div className="flex flex-col">
               <h2 className="text-lg font-black tracking-tighter italic text-white uppercase leading-none">{APP_NAME}</h2>
               <span className="text-[9px] font-black text-slate-500 tracking-[0.25em] mt-1.5 uppercase">Neural Core v4.5</span>
            </div>
          </div>

          <button onClick={createNewSession} className="flex items-center justify-center gap-4 w-full p-5 mb-10 bg-gradient-to-br from-indigo-600 to-blue-700 hover:from-indigo-500 hover:to-blue-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-600/30 active:scale-[0.95] transition-all text-[11px] uppercase tracking-[0.2em]">
            <PlusIcon className="w-5 h-5" /> Initialize Node
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-5">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.35em] px-1 mb-3">Workspace Streams</h3>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-all border ${currentSessionId === s.id ? 'bg-indigo-600/20 text-indigo-300 border-indigo-500/40 shadow-xl' : 'hover:bg-white/5 border-transparent'}`}>
                <span className="truncate flex-1 text-[13px] font-bold tracking-tight">{s.title || 'Nexus Hub'}</span>
                <TrashIcon className="w-4 h-4 opacity-0 group-hover:opacity-100 text-slate-600 hover:text-red-500 transition-all" onClick={(e) => { e.stopPropagation(); setSessions(prev => prev.filter(x => x.id !== s.id)); }} />
              </div>
            ))}
          </div>

          <div className="mt-auto space-y-4 pt-8 border-t border-white/5">
            <button onClick={() => { setShowMemory(true); setShowSidebar(false); }} className="flex items-center gap-5 p-4 w-full rounded-2xl hover:bg-white/5 transition-all group">
              <BotIcon className="w-6 h-6 text-slate-500 group-hover:text-cyan-400 transition-colors" /> <span className="text-[13px] font-black uppercase tracking-widest text-slate-400 group-hover:text-white transition-colors">Neural Vault</span>
            </button>
            <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-5 p-4 w-full rounded-2xl hover:bg-white/5 transition-all group">
              <SettingsIcon className="w-6 h-6 text-slate-500 group-hover:text-indigo-400 transition-colors" /> <span className="text-[13px] font-black uppercase tracking-widest text-slate-400 group-hover:text-white transition-colors">Core Matrix</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Memory Vault Overlay */}
      <aside className={`fixed left-0 top-0 h-full w-80 bg-[#0d0d14]/99 backdrop-blur-[40px] z-[60] transform transition-transform duration-700 cubic-bezier(0.19, 1, 0.22, 1) ${showMemory ? 'translate-x-0' : '-translate-x-full'} border-r border-white/15`}>
        <MemoryPanel memories={memories} onDelete={deleteMemory} onPin={pinMemory} onClose={() => setShowMemory(false)} />
      </aside>

      {/* Core Interaction Engine UI */}
      <main className="flex flex-col flex-1 h-full w-full relative z-10 shadow-inner">
        <header className="px-6 py-5 border-b border-white/10 bg-[#07070a]/80 backdrop-blur-2xl sticky top-0 z-30 flex items-center justify-between shadow-2xl">
          <div className="flex items-center gap-5">
            <button onClick={() => setShowSidebar(true)} className="p-2.5 -ml-2.5 hover:bg-white/10 rounded-2xl transition-all active:scale-90"><MenuIcon className="w-6 h-6 text-slate-300" /></button>
            <div className="flex flex-col">
              <h1 className="text-[13px] font-black tracking-widest text-white uppercase truncate max-w-[160px] italic">{currentSession?.title || 'NEXUS ALPHA'}</h1>
              <div className="flex items-center gap-2 mt-1.5">
                 <span className={`w-2 h-2 rounded-full ${deviceStats.temp > 50 ? 'bg-amber-500' : 'bg-cyan-500 animate-pulse'} shadow-[0_0_10px_rgba(34,211,238,0.7)]`} />
                 <span className="text-[10px] font-black text-slate-500 tracking-widest uppercase">{config.profile} Mode Linked</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-right flex flex-col items-end mr-3">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-[0.25em]">Neural Link</span>
                <span className="text-[12px] font-black text-indigo-400 tabular-nums italic">{isStreaming ? currentTps : '0.0'} TPS</span>
             </div>
             <button onClick={() => setShowSettings(true)} className="p-2.5 hover:bg-white/10 rounded-2xl transition-all active:scale-90"><SettingsIcon className="w-6 h-6 text-slate-400" /></button>
          </div>
        </header>

        {/* Cinematic Chat Interface */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto px-6 py-10 space-y-12 no-scrollbar pb-44 scroll-smooth">
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-12 py-16 animate-in zoom-in-95 duration-[2200ms] cubic-bezier(0.19, 1, 0.22, 1)">
              <div className="relative">
                <AnimatedLogo className="w-32 h-32" />
                <div className="absolute inset-0 bg-cyan-500/10 blur-[70px] rounded-full animate-pulse" />
              </div>
              <div className="space-y-4">
                <h2 className="text-3xl font-black tracking-[0.3em] text-white uppercase italic drop-shadow-[0_0_20px_rgba(255,255,255,0.4)]">{APP_NAME}</h2>
                <p className="text-[12px] text-slate-400 font-bold uppercase tracking-[0.4em] leading-relaxed max-w-[320px] mx-auto opacity-70">Neural Identity Agent | On-Device ARM64 | Professional Tier</p>
              </div>
              <div className="flex flex-col gap-4 w-full max-w-[280px]">
                {['Synthesize Workspace Hub', 'Audit Neural Identity', 'Generate Logic Link'].map(h => (
                  <button key={h} onClick={() => setInput(h)} className="p-5 bg-white/5 backdrop-blur-2xl border border-white/10 rounded-[1.8rem] text-[12px] font-black text-slate-400 hover:text-cyan-400 hover:border-cyan-500/40 transition-all text-left flex items-center justify-between active:scale-[0.96] group shadow-2xl">
                    {h} <PlusIcon className="w-5 h-5 text-indigo-500 group-hover:scale-125 transition-transform" />
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentSession?.messages.map(m => (
            <div key={m.id} className={`flex w-full ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in duration-[900ms] cubic-bezier(0.23, 1, 0.32, 1)`}>
              <div className={`flex flex-col gap-4 max-w-[98%] ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                {m.role === 'user' && m.taskType && (
                  <span className="text-[9px] font-black uppercase tracking-[0.35em] bg-indigo-600/15 text-indigo-300 px-4 py-1.5 rounded-full border border-indigo-500/30">{m.taskType} NODE</span>
                )}

                {m.role === 'assistant' && activeSteps.length > 0 && m.id === currentSession?.messages[currentSession?.messages.length - 1].id && (
                  <div className="flex flex-wrap gap-3 mb-3">
                    {activeSteps.map((s, idx) => (
                      <div key={idx} className={`flex items-center gap-3 px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-[0.25em] border transition-all duration-500 ${
                        s.status === 'active' ? 'bg-cyan-600 text-white border-cyan-400 shadow-[0_0_20px_rgba(8,145,178,0.6)] animate-pulse' : 
                        s.status === 'complete' ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/40' : 
                        'bg-white/5 text-slate-700 border-transparent opacity-50'
                      }`}>
                        {s.label}
                      </div>
                    ))}
                  </div>
                )}

                <div className={`p-6 rounded-[2.5rem] text-[14.5px] leading-[1.7] shadow-2xl transition-all duration-700 ${
                  m.role === 'user' 
                    ? 'bg-gradient-to-br from-indigo-600 to-blue-800 text-white rounded-tr-none font-bold shadow-indigo-900/30' 
                    : 'bg-[#12121c]/90 backdrop-blur-3xl text-slate-100 rounded-tl-none border border-white/10 shadow-black/50'
                }`}>
                  {renderContent(m.content || '')}
                  {isStreaming && !m.content && m.role === 'assistant' && (
                    <div className="flex gap-2.5 py-3"><div className="w-2.5 h-2.5 bg-cyan-400 rounded-full animate-bounce" /><div className="w-2.5 h-2.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.2s]" /><div className="w-2.5 h-2.5 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.4s]" /></div>
                  )}
                </div>

                {m.toolCalls && m.toolCalls.length > 0 && (
                  <div className="mt-3 w-full flex flex-col gap-4">
                    {m.toolCalls.map((tc, idx) => (
                      <div key={idx} className="bg-cyan-600/10 border border-cyan-500/30 p-5 rounded-[2.2rem] backdrop-blur-xl animate-in zoom-in-95 duration-500">
                        <div className="flex items-center justify-between mb-3">
                          <span className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.35em]">Neural Op: {tc.name}</span>
                          <span className="text-[9px] font-black text-emerald-500 uppercase bg-emerald-500/20 px-4 py-1.5 rounded-full border border-emerald-500/20 shadow-sm">Verified</span>
                        </div>
                        <p className="text-[11.5px] font-bold text-slate-400 italic leading-relaxed">System Response: {tc.result}</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>

        {/* Premium Input Dashboard */}
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-[#07070a] via-[#07070a]/95 to-transparent z-40">
          <div className="bg-[#1c1c2b]/90 backdrop-blur-[45px] p-4 rounded-[2.8rem] border border-white/15 shadow-[0_-25px_65px_rgba(0,0,0,0.7)] flex items-end gap-5 focus-within:ring-2 ring-indigo-500/60 transition-all duration-1000">
            <button onClick={toggleListening} className={`p-4 rounded-full transition-all duration-500 ${isListening ? 'bg-red-500 text-white shadow-[0_0_25px_rgba(239,68,68,0.7)]' : 'hover:bg-white/15 text-slate-400'}`}>
              <MicIcon className="w-6 h-6" active={isListening} />
            </button>
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isStreaming ? "Neural Link Active..." : "Initiate neural prompt..."}
              disabled={isStreaming}
              className="flex-1 bg-transparent border-none focus:ring-0 text-[14.5px] p-2.5 no-scrollbar resize-none max-h-44 min-h-[52px] placeholder:text-slate-700 font-bold text-white transition-all"
              rows={1}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
            />
            <button onClick={handleSend} disabled={!input.trim() || isStreaming} className={`p-4.5 rounded-full transition-all duration-500 flex items-center justify-center ${!input.trim() || isStreaming ? 'bg-white/5 text-slate-800' : 'bg-gradient-to-br from-indigo-500 via-blue-600 to-indigo-800 text-white shadow-2xl shadow-indigo-600/40 hover:scale-105 active:scale-90'}`}>
              <SendIcon className="w-6 h-6" />
            </button>
          </div>
        </div>
      </main>

      {/* Settings Panel Overlay */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center">
          <div className="absolute inset-0 bg-black/98 backdrop-blur-[50px]" onClick={() => setShowSettings(false)} />
          <div className="relative bg-[#0d0d14] w-full max-w-sm rounded-t-[3.8rem] sm:rounded-[3.8rem] p-12 space-y-12 border-t border-white/15 animate-in slide-in-from-bottom-full duration-1000 cubic-bezier(0.19, 1, 0.22, 1) shadow-2xl">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black tracking-tighter text-white uppercase italic tracking-widest">Core Matrix</h2>
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.45em] mt-2">Neural Link Governance</span>
              </div>
              <button onClick={() => setShowSettings(false)} className="w-12 h-12 flex items-center justify-center bg-white/10 rounded-full text-slate-300 hover:text-white transition-all active:scale-90">×</button>
            </div>

            <div className="space-y-10">
              <div className="space-y-5">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-[0.45em] px-1">Neural Stream Model</label>
                <div className="space-y-4">
                  {AVAILABLE_MODELS.map(m => (
                    <div key={m.id} onClick={() => setConfig({ ...config, activeModelId: m.id })} className={`p-6 rounded-[2.2rem] border-2 transition-all duration-500 cursor-pointer ${config.activeModelId === m.id ? 'border-cyan-500 bg-cyan-500/20 shadow-[0_0_35px_rgba(34,211,238,0.3)]' : 'border-white/5 bg-white/[0.05] hover:bg-white/[0.1]'}`}>
                      <div className="flex justify-between items-center mb-3">
                        <span className={`text-[15px] font-black ${config.activeModelId === m.id ? 'text-cyan-400' : 'text-white'}`}>{m.name}</span>
                        <span className="text-[9px] font-black bg-white/20 text-slate-400 px-3.5 py-1.5 rounded-full uppercase border border-white/10">{m.version}</span>
                      </div>
                      <p className="text-[11.5px] text-slate-500 font-bold leading-relaxed">{m.description}</p>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-4">
                   <label className="text-[11px] font-black text-slate-500 uppercase tracking-[0.35em]">Power Core</label>
                   <div className="grid grid-cols-3 bg-white/5 p-2 rounded-[1.8rem] border border-white/15">
                     {(['Eco', 'Balanced', 'Performance'] as PerformanceMode[]).map(p => (
                       <button key={p} onClick={() => setConfig({...config, profile: p})} className={`py-4 text-[10px] font-black rounded-2xl transition-all ${config.profile === p ? 'bg-indigo-600 text-white shadow-2xl shadow-indigo-600/40' : 'text-slate-500 hover:text-slate-300'}`}>{p[0]}</button>
                     ))}
                   </div>
                 </div>
                 <div className="space-y-4">
                   <label className="text-[11px] font-black text-slate-500 uppercase tracking-[0.35em]">Vault Sync</label>
                   <div onClick={() => setConfig({ ...config, useCognitiveMemory: !config.useCognitiveMemory })} className={`w-full py-5 rounded-[1.8rem] text-[11px] font-black text-center cursor-pointer transition-all border-2 flex items-center justify-center gap-4 ${config.useCognitiveMemory ? 'border-cyan-500 bg-cyan-500/20 text-cyan-400 shadow-[0_0_25px_rgba(34,211,238,0.25)]' : 'border-white/15 text-slate-700 hover:border-white/40'}`}>
                     <div className={`w-3 h-3 rounded-full ${config.useCognitiveMemory ? 'bg-cyan-400 shadow-[0_0_15px_cyan]' : 'bg-slate-800'}`} />
                     {config.useCognitiveMemory ? 'Linked' : 'Offline'}
                   </div>
                 </div>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full py-6.5 bg-gradient-to-r from-white via-slate-100 to-slate-400 text-black rounded-[2.2rem] font-black text-[14px] uppercase tracking-[0.4em] shadow-2xl transition-transform active:scale-95 hover:brightness-110">Commit Neural Sync</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  ChatSession, Message, LocalModel, 
  AppConfig, DeviceStats, ReasoningStep, PerformanceMode, TaskType, MemoryEntry
} from './types';
import { AVAILABLE_MODELS, DEFAULT_CONFIG, STORAGE_KEYS, APP_NAME } from './constants';
import { storageService } from './services/storageService';
import { localInference } from './services/localInference';
import { initLLM } from './native/LocalLLM';
import { 
  SendIcon, MenuIcon, PlusIcon, SettingsIcon, 
  TrashIcon, BotIcon, MicIcon, SpeakerIcon
} from './components/Icons';
import { MemoryPanel } from './app/components/MemoryPanel';
import { SplashScreen } from './components/SplashScreen';
import { AnimatedLogo } from './components/AnimatedLogo';

const App: React.FC = () => {
  const [booting, setBooting] = useState(true);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [deviceStats, setDeviceStats] = useState<DeviceStats>({ 
    ramUsage: 1.2, totalRam: 12, temp: 34, npuLoad: 4, batteryLevel: 98 
  });
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [activeSteps, setActiveSteps] = useState<ReasoningStep[]>([]);
  const [showSidebar, setShowSidebar] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showMemory, setShowMemory] = useState(false);
  const [currentTps, setCurrentTps] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [memories, setMemories] = useState<MemoryEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    // Initialize Local Engine
    initLLM("/data/data/com.nexus/models/qwen2.5-coder-7b.gguf");

    // Neural Node Initialization Phase
    const loaded = storageService.loadSessions();
    if (loaded.length > 0) {
      setSessions(loaded);
      setCurrentSessionId(loaded[0].id);
    } else createNewSession();

    const loadedConfig = storageService.loadConfig();
    if (loadedConfig) setConfig(loadedConfig);

    const loadedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
    if (loadedMemories) setMemories(JSON.parse(loadedMemories));
  }, []);

  const handleFinishBooting = useCallback(() => {
    setBooting(false);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      const multiplier = config.profile === 'Performance' ? 1.5 : config.profile === 'Eco' ? 0.5 : 1;
      setDeviceStats(prev => ({
        ...prev,
        ramUsage: +(prev.ramUsage + (isStreaming ? 0.4 * multiplier : -0.1)).toFixed(2),
        temp: isStreaming ? Math.min(prev.temp + 0.5 * multiplier, 55) : Math.max(prev.temp - 0.2, 30),
        npuLoad: isStreaming ? 75 * multiplier : 2,
        batteryLevel: Math.max(0, prev.batteryLevel - (isStreaming ? 0.03 * multiplier : 0.001))
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isStreaming, config.profile]);

  useEffect(() => { storageService.saveSessions(sessions); }, [sessions]);
  useEffect(() => { storageService.saveConfig(config); }, [config]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [currentSession?.messages, isStreaming, activeSteps]);

  const createNewSession = () => {
    const s: ChatSession = {
      id: Date.now().toString(),
      title: 'Nexus Node Alpha',
      messages: [],
      createdAt: Date.now(),
      lastModified: Date.now(),
      modelId: config.activeModelId
    };
    setSessions(prev => [s, ...prev]);
    setCurrentSessionId(s.id);
    setShowSidebar(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const taskType = localInference.classifyTask(input);
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: input, 
      timestamp: Date.now(),
      taskType
    };

    setSessions(prev => prev.map(s => s.id === currentSessionId ? {
      ...s, messages: [...s.messages, userMsg],
      title: s.messages.length === 0 ? input.slice(0, 24) : s.title
    } : s));

    setInput('');
    setIsStreaming(true);
    setActiveSteps([]);

    const assistantId = (Date.now() + 1).toString();
    const assistantMsg: Message = { id: assistantId, role: 'assistant', content: '', timestamp: Date.now(), reasoningSteps: [] };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s));

    await localInference.streamResponse(
      config,
      [...(currentSession?.messages || []), userMsg],
      (newSteps) => setActiveSteps(newSteps),
      (token, tps) => {
        setCurrentTps(tps);
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            const msgs = [...s.messages];
            const idx = msgs.findIndex(m => m.id === assistantId);
            if (idx !== -1) msgs[idx] = { ...msgs[idx], content: msgs[idx].content + token, tokensPerSec: tps };
            return { ...s, messages: msgs };
          }
          return s;
        }));
      },
      (full, sources, toolCalls) => {
        setIsStreaming(false);
        setSessions(prev => prev.map(s => s.id === currentSessionId ? {
          ...s, messages: s.messages.map(m => m.id === assistantId ? { ...m, sources, toolCalls, reasoningSteps: [], isPersonalized: sources.length > 0 } : m)
        } : s));

        const updatedMemories = localStorage.getItem(STORAGE_KEYS.COGNITIVE_MEMORY);
        if (updatedMemories) setMemories(JSON.parse(updatedMemories));

        if (config.voiceEnabled) speak(full);
      },
      (err) => { setIsStreaming(false); console.error(err); }
    );
  };

  const deleteMemory = (id: string) => {
    const updated = memories.filter(m => m.id !== id);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const pinMemory = (id: string) => {
    const updated = memories.map(m => m.id === id ? { ...m, isPinned: !m.isPinned } : m);
    setMemories(updated);
    localStorage.setItem(STORAGE_KEYS.COGNITIVE_MEMORY, JSON.stringify(updated));
  };

  const toggleListening = () => {
    if (isListening) setIsListening(false);
    else {
      setIsListening(true);
      setTimeout(() => {
        if (isListening) setInput("Analyze my Nexus workspace.");
        setIsListening(false);
      }, 1500);
    }
  };

  const speak = (text: string) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text.slice(0, 150));
      window.speechSynthesis.speak(utterance);
    }
  };

  const renderContent = (content: string) => {
    const blocks = content.split(/(\n\n|```[\s\S]*?```)/g);
    return blocks.map((block, i) => {
      const trimmed = block.trim();
      if (!trimmed) return null;
      if (trimmed.startsWith('```')) {
        const lines = trimmed.split('\n');
        const lang = lines[0].replace('```', '').trim() || 'code';
        const code = lines.slice(1, -1).join('\n');
        return (
          <div key={i} className="my-3 rounded-2xl overflow-hidden border border-white/10 bg-black/40 backdrop-blur-md font-mono shadow-xl">
             <div className="bg-white/5 px-4 py-2 flex items-center justify-between border-b border-white/5">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{lang}</span>
                <button onClick={() => navigator.clipboard.writeText(code)} className="text-[9px] text-indigo-400 font-black uppercase hover:text-white transition-colors">Copy Node</button>
             </div>
             <div className="p-4 overflow-x-auto no-scrollbar">
                <pre className="text-[11px] leading-relaxed text-indigo-100/90 whitespace-pre">{code}</pre>
             </div>
          </div>
        );
      }
      return <p key={i} className="mb-4 last:mb-0 leading-[1.65] font-medium text-[13px] text-slate-200 whitespace-pre-wrap">{trimmed}</p>;
    });
  };

  if (booting) {
    return <SplashScreen duration={5000} onFinish={handleFinishBooting} />;
  }

  return (
    <div className="flex h-full w-full max-w-md mx-auto bg-[#07070a] text-slate-100 overflow-hidden relative font-sans transition-all duration-700 ease-out opacity-0 animate-[nexus-fade-in_1s_forwards]">
      <style>{`
        @keyframes nexus-fade-in {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>

      {/* Background Cinematic Lighting */}
      <div className="absolute inset-0 pointer-events-none opacity-20">
         <div className="absolute top-[-20%] left-[-20%] w-[80%] h-[80%] bg-blue-600 rounded-full blur-[140px]" />
         <div className="absolute bottom-[-20%] right-[-20%] w-[80%] h-[80%] bg-purple-600 rounded-full blur-[140px]" />
      </div>

      {/* Sidebar Navigation */}
      {(showSidebar || showMemory) && <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-40" onClick={() => { setShowSidebar(false); setShowMemory(false); }} />}

      <aside className={`fixed left-0 top-0 h-full w-72 bg-[#0d0d14]/95 backdrop-blur-2xl z-50 transform transition-transform duration-700 cubic-bezier(0.19, 1, 0.22, 1) ${showSidebar ? 'translate-x-0' : '-translate-x-full'} border-r border-white/10 shadow-[30px_0_60px_rgba(0,0,0,0.5)]`}>
        <div className="p-6 flex flex-col h-full">
          <div className="flex items-center gap-3 mb-10">
            <AnimatedLogo className="w-10 h-10" />
            <div className="flex flex-col">
               <h2 className="text-md font-black tracking-tighter italic text-white uppercase leading-none">{APP_NAME}</h2>
               <span className="text-[8px] font-black text-slate-500 tracking-[0.2em] mt-1.5 uppercase">Neural Node v4.5</span>
            </div>
          </div>

          <button onClick={createNewSession} className="flex items-center justify-center gap-4 w-full p-4 mb-8 bg-gradient-to-r from-indigo-600 to-blue-600 hover:from-indigo-500 hover:to-blue-500 text-white rounded-2xl font-black shadow-2xl shadow-indigo-600/30 active:scale-[0.96] transition-all text-xs uppercase tracking-widest">
            <PlusIcon className="w-4 h-4" /> Initialize Link
          </button>

          <div className="flex-1 overflow-y-auto no-scrollbar space-y-4">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] px-1 mb-2">Workspace Hub</h3>
            {sessions.map(s => (
              <div key={s.id} onClick={() => { setCurrentSessionId(s.id); setShowSidebar(false); }} className={`group flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-all border ${currentSessionId === s.id ? 'bg-indigo-600/20 text-indigo-300 border-indigo-500/40 shadow-lg' : 'hover:bg-white/5 border-transparent'}`}>
                <span className="truncate flex-1 text-[12px] font-bold tracking-tight">{s.title || 'Nexus Stream'}</span>
                <TrashIcon className="w-4 h-4 opacity-0 group-hover:opacity-100 text-slate-600 hover:text-red-500 transition-all" onClick={(e) => { e.stopPropagation(); setSessions(prev => prev.filter(x => x.id !== s.id)); }} />
              </div>
            ))}
          </div>

          <div className="mt-auto space-y-3 pt-6 border-t border-white/5">
            <button onClick={() => { setShowMemory(true); setShowSidebar(false); }} className="flex items-center gap-4 p-4 w-full rounded-2xl hover:bg-white/5 transition-all group">
              <BotIcon className="w-5 h-5 text-slate-500 group-hover:text-cyan-400 transition-colors" /> <span className="text-[12px] font-black uppercase tracking-widest text-slate-400 group-hover:text-white transition-colors">Cognitive Vault</span>
            </button>
            <button onClick={() => { setShowSettings(true); setShowSidebar(false); }} className="flex items-center gap-4 p-4 w-full rounded-2xl hover:bg-white/5 transition-all group">
              <SettingsIcon className="w-5 h-5 text-slate-500 group-hover:text-indigo-400 transition-colors" /> <span className="text-[12px] font-black uppercase tracking-widest text-slate-400 group-hover:text-white transition-colors">Core Matrix</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Memory Panel overlay */}
      <aside className={`fixed left-0 top-0 h-full w-80 bg-[#0d0d14]/98 backdrop-blur-3xl z-[60] transform transition-transform duration-700 cubic-bezier(0.19, 1, 0.22, 1) ${showMemory ? 'translate-x-0' : '-translate-x-full'} border-r border-white/10 shadow-[30px_0_60px_rgba(0,0,0,0.5)]`}>
        <MemoryPanel memories={memories} onDelete={deleteMemory} onPin={pinMemory} onClose={() => setShowMemory(false)} />
      </aside>

      {/* Main Experience */}
      <main className="flex flex-col flex-1 h-full w-full relative z-10 shadow-inner">
        <header className="px-5 py-4 border-b border-white/10 bg-[#07070a]/80 backdrop-blur-2xl sticky top-0 z-30 flex items-center justify-between shadow-2xl">
          <div className="flex items-center gap-4">
            <button onClick={() => setShowSidebar(true)} className="p-2 -ml-2 hover:bg-white/10 rounded-2xl transition-all active:scale-90"><MenuIcon className="w-6 h-6 text-slate-300" /></button>
            <div className="flex flex-col">
              <h1 className="text-[12px] font-black tracking-widest text-white uppercase truncate max-w-[150px] italic">{currentSession?.title || 'NEXUS NODE'}</h1>
              <div className="flex items-center gap-1.5 mt-1">
                 <span className={`w-1.5 h-1.5 rounded-full ${deviceStats.temp > 50 ? 'bg-amber-500' : 'bg-cyan-500 animate-pulse'} shadow-[0_0_8px_rgba(34,211,238,0.6)]`} />
                 <span className="text-[9px] font-black text-slate-500 tracking-widest uppercase">{config.profile} Matrix Active</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <div className="text-right flex flex-col items-end mr-2">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Neural Link</span>
                <span className="text-[11px] font-black text-indigo-400 tabular-nums">{isStreaming ? currentTps : '0.0'} TPS</span>
             </div>
             <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-white/10 rounded-2xl transition-all active:scale-90"><SettingsIcon className="w-5 h-5 text-slate-400" /></button>
          </div>
        </header>

        {/* Chat Feed */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto px-5 py-8 space-y-12 no-scrollbar pb-40 scroll-smooth">
          {currentSession?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-12 py-16 animate-in zoom-in-95 duration-[2000ms] cubic-bezier(0.19, 1, 0.22, 1)">
              <div className="relative">
                <AnimatedLogo className="w-28 h-28" />
                <div className="absolute inset-0 bg-cyan-500/10 blur-[60px] rounded-full animate-pulse" />
              </div>
              <div className="space-y-4">
                <h2 className="text-2xl font-black tracking-[0.3em] text-white uppercase italic drop-shadow-[0_0_20px_rgba(255,255,255,0.4)]">{APP_NAME}</h2>
                <p className="text-[12px] text-slate-400 font-bold uppercase tracking-[0.5em] leading-relaxed max-w-[300px] mx-auto opacity-70">Personal AI Node | local ARM64 Inference | Cinematic UX</p>
              </div>
              <div className="flex flex-col gap-4 w-full max-w-[260px]">
                {['Architect Nexus Node', 'Audit System Identity', 'Generate Logic Stream'].map(h => (
                  <button key={h} onClick={() => setInput(h)} className="p-4 bg-white/5 backdrop-blur-2xl border border-white/10 rounded-2xl text-[11px] font-black text-slate-400 hover:text-cyan-400 hover:border-cyan-500/30 transition-all text-left flex items-center justify-between active:scale-[0.97] group shadow-xl">
                    {h} <PlusIcon className="w-4 h-4 text-indigo-500 group-hover:scale-125 transition-transform" />
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentSession?.messages.map(m => (
            <div key={m.id} className={`flex w-full ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in duration-700 cubic-bezier(0.23, 1, 0.32, 1)`}>
              <div className={`flex flex-col gap-4 max-w-[96%] ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                {m.role === 'user' && m.taskType && (
                  <span className="text-[9px] font-black uppercase tracking-[0.3em] bg-indigo-600/15 text-indigo-300 px-3 py-1 rounded-full border border-indigo-500/30">{m.taskType} NODE</span>
                )}

                {m.role === 'assistant' && activeSteps.length > 0 && m.id === currentSession?.messages[currentSession?.messages.length - 1].id && (
                  <div className="flex flex-wrap gap-2.5 mb-2">
                    {activeSteps.map((s, idx) => (
                      <div key={idx} className={`flex items-center gap-2.5 px-3.5 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] border transition-all duration-500 ${
                        s.status === 'active' ? 'bg-cyan-600 text-white border-cyan-400 shadow-[0_0_15px_rgba(8,145,178,0.5)] animate-pulse' : 
                        s.status === 'complete' ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/30' : 
                        'bg-white/5 text-slate-700 border-transparent opacity-50'
                      }`}>
                        {s.label}
                      </div>
                    ))}
                  </div>
                )}

                <div className={`p-6 rounded-[2.5rem] text-[14px] leading-[1.65] shadow-2xl transition-all duration-700 ${
                  m.role === 'user' 
                    ? 'bg-gradient-to-br from-indigo-600 to-blue-800 text-white rounded-tr-none font-bold' 
                    : 'bg-[#12121c]/90 backdrop-blur-3xl text-slate-100 rounded-tl-none border border-white/10'
                }`}>
                  {renderContent(m.content || '')}
                  {isStreaming && !m.content && m.role === 'assistant' && (
                    <div className="flex gap-2.5 py-2.5"><div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" /><div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.2s]" /><div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce [animation-delay:0.4s]" /></div>
                  )}
                </div>

                {m.toolCalls && m.toolCalls.length > 0 && (
                  <div className="mt-2 w-full flex flex-col gap-4">
                    {m.toolCalls.map((tc, idx) => (
                      <div key={idx} className="bg-cyan-600/10 border border-cyan-500/30 p-5 rounded-[2rem] backdrop-blur-xl animate-in zoom-in-95 duration-500">
                        <div className="flex items-center justify-between mb-2">
                          <span className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.3em]">Neural Tool: {tc.name}</span>
                          <span className="text-[9px] font-black text-emerald-500 uppercase bg-emerald-500/15 px-3 py-1 rounded-full border border-emerald-500/20">Synced</span>
                        </div>
                        <p className="text-[11px] font-bold text-slate-400 italic leading-relaxed">System Result: {tc.result}</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>

        {/* Input Interface */}
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-[#07070a] via-[#07070a]/95 to-transparent z-40">
          <div className="bg-[#1c1c2b]/90 backdrop-blur-3xl p-3.5 rounded-[2.5rem] border border-white/15 shadow-[0_-20px_60px_rgba(0,0,0,0.6)] flex items-end gap-4 focus-within:ring-2 ring-indigo-500/50 transition-all duration-700">
            <button onClick={toggleListening} className={`p-3.5 rounded-full transition-all duration-500 ${isListening ? 'bg-red-500 text-white shadow-[0_0_20px_rgba(239,68,68,0.5)]' : 'hover:bg-white/10 text-slate-400'}`}>
              <MicIcon className="w-6 h-6" active={isListening} />
            </button>
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isStreaming ? "Neural processing..." : "Neural prompt link..."}
              disabled={isStreaming}
              className="flex-1 bg-transparent border-none focus:ring-0 text-[14px] p-2.5 no-scrollbar resize-none max-h-36 min-h-[44px] placeholder:text-slate-700 font-bold text-white transition-all"
              rows={1}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
            />
            <button onClick={handleSend} disabled={!input.trim() || isStreaming} className={`p-4 rounded-full transition-all duration-500 flex items-center justify-center ${!input.trim() || isStreaming ? 'bg-white/5 text-slate-800' : 'bg-gradient-to-br from-indigo-500 via-blue-600 to-indigo-700 text-white shadow-2xl shadow-indigo-600/40 hover:scale-105 active:scale-90'}`}>
              <SendIcon className="w-6 h-6" />
            </button>
          </div>
        </div>
      </main>

      {/* Settings Panel */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center">
          <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={() => setShowSettings(false)} />
          <div className="relative bg-[#0d0d14] w-full max-w-sm rounded-t-[3.5rem] sm:rounded-[3.5rem] p-10 space-y-10 border-t border-white/15 animate-in slide-in-from-bottom-96 duration-1000 cubic-bezier(0.19, 1, 0.22, 1) shadow-2xl">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <h2 className="text-xl font-black tracking-tighter text-white uppercase italic tracking-widest">Core Matrix</h2>
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.4em] mt-2">Neural System Governance</span>
              </div>
              <button onClick={() => setShowSettings(false)} className="w-10 h-10 flex items-center justify-center bg-white/10 rounded-full text-slate-300 hover:text-white transition-all active:scale-90">×</button>
            </div>

            <div className="space-y-8">
              <div className="space-y-4">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-[0.4em] px-1">Active Neural Model</label>
                <div className="space-y-4">
                  {AVAILABLE_MODELS.map(m => (
                    <div key={m.id} onClick={() => setConfig({ ...config, activeModelId: m.id })} className={`p-5 rounded-[2rem] border-2 transition-all duration-500 cursor-pointer ${config.activeModelId === m.id ? 'border-cyan-500 bg-cyan-500/15 shadow-[0_0_30px_rgba(34,211,238,0.2)]' : 'border-white/5 bg-white/[0.04] hover:bg-white/[0.08]'}`}>
                      <div className="flex justify-between items-center mb-2">
                        <span className={`text-[14px] font-black ${config.activeModelId === m.id ? 'text-cyan-400' : 'text-white'}`}>{m.name}</span>
                        <span className="text-[9px] font-black bg-white/15 text-slate-400 px-3 py-1.5 rounded-full uppercase border border-white/10">{m.version}</span>
                      </div>
                      <p className="text-[11px] text-slate-500 font-bold leading-relaxed">{m.description}</p>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-3">
                   <label className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Power Node</label>
                   <div className="grid grid-cols-3 bg-white/5 p-2 rounded-[1.5rem] border border-white/10">
                     {(['Eco', 'Balanced', 'Performance'] as PerformanceMode[]).map(p => (
                       <button key={p} onClick={() => setConfig({...config, profile: p})} className={`py-3.5 text-[10px] font-black rounded-2xl transition-all ${config.profile === p ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-500 hover:text-slate-300'}`}>{p[0]}</button>
                     ))}
                   </div>
                 </div>
                 <div className="space-y-3">
                   <label className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Cognitive Sync</label>
                   <div onClick={() => setConfig({ ...config, useCognitiveMemory: !config.useCognitiveMemory })} className={`w-full py-4 rounded-[1.5rem] text-[11px] font-black text-center cursor-pointer transition-all border-2 flex items-center justify-center gap-4 ${config.useCognitiveMemory ? 'border-cyan-500 bg-cyan-500/15 text-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.15)]' : 'border-white/10 text-slate-700 hover:border-white/30'}`}>
                     <div className={`w-2.5 h-2.5 rounded-full ${config.useCognitiveMemory ? 'bg-cyan-400 shadow-[0_0_12px_cyan]' : 'bg-slate-800'}`} />
                     {config.useCognitiveMemory ? 'Linked' : 'Offline'}
                   </div>
                 </div>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full py-6 bg-gradient-to-r from-white via-slate-100 to-slate-300 text-black rounded-[2rem] font-black text-[13px] uppercase tracking-[0.3em] shadow-2xl transition-transform active:scale-95 hover:brightness-110">Commit Neural Node</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { AnimatedLogo } from './AnimatedLogo';
import { APP_NAME, TAGLINE } from '../constants';

interface SplashScreenProps {
  duration: number;
  onFinish: () => void;
}

export const SplashScreen: React.FC<SplashScreenProps> = ({ duration, onFinish }) => {
  const [stage, setStage] = useState<'converge' | 'ignite' | 'reveal' | 'stabilize' | 'exit'>('converge');
  const onFinishRef = useRef(onFinish);

  // Update ref to ensure we always have the latest callback without re-triggering effects
  useEffect(() => {
    onFinishRef.current = onFinish;
  }, [onFinish]);

  // Procedural particles shooting from screen edges to the center for cinematic convergence
  const particles = useMemo(() => {
    return Array.from({ length: 90 }).map((_, i) => {
      const angle = Math.random() * Math.PI * 2;
      const radius = 180 + Math.random() * 60; // Start outside the center focus
      return {
        id: i,
        startX: Math.cos(angle) * radius,
        startY: Math.sin(angle) * radius,
        delay: Math.random() * 900,
        size: Math.random() * 3.5 + 1,
        color: i % 3 === 0 ? '#22d3ee' : i % 3 === 1 ? '#8b5cf6' : '#ffffff',
        speed: 900 + Math.random() * 1100
      };
    });
  }, []);

  useEffect(() => {
    // Cinematic timeline orchestration - only runs once on mount
    const tIgnite = setTimeout(() => setStage('ignite'), 1000);
    const tReveal = setTimeout(() => setStage('reveal'), 1800);
    const tStabilize = setTimeout(() => setStage('stabilize'), 3000);
    const tExit = setTimeout(() => setStage('exit'), duration - 800);
    const tFinish = setTimeout(() => {
      onFinishRef.current();
    }, duration);

    return () => {
      clearTimeout(tIgnite);
      clearTimeout(tReveal);
      clearTimeout(tStabilize);
      clearTimeout(tExit);
      clearTimeout(tFinish);
    };
  }, [duration]);

  return (
    <div className={`fixed inset-0 z-[9999] bg-[#07070a] flex flex-col items-center justify-center transition-all duration-1000 cubic-bezier(0.19, 1, 0.22, 1) ${
      stage === 'exit' ? 'opacity-0 scale-125 blur-3xl' : 'opacity-100 scale-100 blur-0'
    }`}>

      {/* 60FPS Particle Convergence Layer */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        {particles.map((p) => (
          <div 
            key={p.id}
            className={`absolute w-1 h-1 rounded-full transition-all cubic-bezier(0.19, 1, 0.22, 1)`}
            style={{
              top: `calc(50% + ${stage === 'converge' ? p.startY : 0}%)`,
              left: `calc(50% + ${stage === 'converge' ? p.startX : 0}%)`,
              opacity: stage === 'converge' ? 0.8 : 0,
              backgroundColor: p.color,
              transform: stage === 'converge' ? `scale(1.5)` : `scale(0)`,
              transitionDuration: `${p.speed}ms`,
              transitionDelay: `${p.delay}ms`,
              boxShadow: `0 0 15px ${p.color}`,
              filter: 'blur(0.5px)'
            }}
          />
        ))}
      </div>

      {/* Neural Link Ignite Flash */}
      <div className={`absolute inset-0 bg-white pointer-events-none transition-opacity duration-1000 ${
        stage === 'ignite' ? 'opacity-10' : 'opacity-0'
      }`} />

      {/* Atmospheric Ground Glow */}
      <div className={`absolute bottom-[-15%] left-1/2 -translate-x-1/2 w-[160%] h-[50%] bg-cyan-500/10 rounded-full blur-[160px] transition-opacity duration-[3000ms] ${
        stage !== 'converge' ? 'opacity-100' : 'opacity-0'
      }`} />

      {/* Main Branding Experience */}
      <div className="relative flex flex-col items-center justify-center z-10">

        {/* Animated Logo Container with smooth acceleration */}
        <div className={`transition-all duration-[1600ms] cubic-bezier(0.34, 1.56, 0.64, 1) ${
          stage === 'converge' ? 'scale-0 opacity-0 rotate-[-270deg] blur-3xl' : 'scale-100 opacity-100 rotate-0 blur-0'
        }`}>
          <AnimatedLogo className="w-52 h-52 mb-16" animated={stage !== 'exit'} />
        </div>

        {/* Professional Typography Reveal System */}
        <div className="flex flex-col items-center px-6">
          <div className="relative overflow-hidden">
            <h1 className={`text-6xl font-black tracking-[0.5em] text-white italic transition-all duration-[1600ms] cubic-bezier(0.23, 1, 0.32, 1) ${
              ['reveal', 'stabilize', 'exit'].includes(stage) 
                ? 'opacity-100 translate-y-0' 
                : 'opacity-0 translate-y-24 blur-xl'
            }`}>
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-white via-cyan-200 to-indigo-400 drop-shadow-[0_0_30px_rgba(34,211,238,0.3)]">
                {APP_NAME}
              </span>
            </h1>

            {/* Cinematic Scanning Text Shine */}
            <div className={`absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent -translate-x-full ${
              stage === 'reveal' ? 'animate-[nexus-text-shine_2.5s_ease-in-out_forwards]' : 'hidden'
            }`} />
          </div>

          {/* Energy Divider Beam */}
          <div className={`mt-10 h-[2px] bg-gradient-to-r from-transparent via-cyan-400/80 to-transparent transition-all duration-[2500ms] ${
            ['reveal', 'stabilize', 'exit'].includes(stage) ? 'w-64 opacity-100' : 'w-0 opacity-0'
          }`}>
             <div className="absolute top-0 left-0 w-full h-full bg-cyan-400 blur-[5px] opacity-40 animate-pulse" />
          </div>

          <p className={`mt-12 text-[11px] font-black text-slate-400 uppercase tracking-[0.9em] transition-all duration-1200 delay-700 ${
            ['stabilize', 'exit'].includes(stage) ? 'opacity-80 translate-y-0' : 'opacity-0 translate-y-8'
          }`}>
            {TAGLINE}
          </p>
        </div>
      </div>

      {/* Environmental Textures */}
      {/* 1. Perspective Vignette */}
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.95)_100%)]" />

      {/* 2. Neural Fiber Overlay (Scanlines) */}
      <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.08)_50%),linear-gradient(90deg,rgba(255,0,0,0.01),rgba(0,255,0,0.01),rgba(34,211,238,0.02))] bg-[length:100%_4px,4px_100%] z-[60] opacity-40" />

      <style>{`
        @keyframes nexus-text-shine {
          0% { transform: translateX(-150%) skewX(-30deg); }
          100% { transform: translateX(300%) skewX(-30deg); }
        }
      `}</style>
    </div>
  );
};
